 48→export function loadServerConfig(): ServerConfig {
 49→  const inferenceProvider = parseInferenceProvider();
 50→
 51→  const openRouterApiKey = inferenceProvider === "openrouter"
 52→    ? requireEnv("OPENROUTER_API_KEY")
 53→    : Bun.env.OPENROUTER_API_KEY?.trim() || undefined;
 54→
 55→  const ollamaBaseUrl = inferenceProvider === "ollama"
 56→    ? (Bun.env.OLLAMA_BASE_URL?.trim() || "http://127.0.0.1:11434")
 57→    : undefined;
 58→
 59→  const extractionStoreThreshold = parseUnitInterval(
 60→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 61→    "EXTRACTION_STORE_THRESHOLD",
 62→  );
 63→
 64→  const extractionDisplayThreshold = parseUnitInterval(
 65→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 66→    "EXTRACTION_DISPLAY_THRESHOLD",
 67→  );
 68→
 69→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 70→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 71→  }
 72→
 73→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 74→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 75→  const pmAgentModelId = optionalEnv("PM_AGENT_MODEL") ?? extractionModelId;
 76→  const analyticsAgentModelId = requireEnv("ANALYTICS_MODEL");
 77→  const surrealUrl = requireEnv("SURREAL_URL");
 78→  const surrealUsername = requireEnv("SURREAL_USERNAME");
 79→  const surrealPassword = requireEnv("SURREAL_PASSWORD");
 80→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 81→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 82→
 83→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 84→  const observerModelId = optionalEnv("OBSERVER_MODEL") ?? extractionModelId;
 85→  const scorerModelId = optionalEnv("SCORER_MODEL") ?? extractionModelId;
 86→  const githubWebhookSecret = optionalEnv("GITHUB_WEBHOOK_SECRET");
 87→  const betterAuthSecret = requireEnv("BETTER_AUTH_SECRET");
 88→  const betterAuthUrl = requireEnv("BETTER_AUTH_URL");
 89→  const githubClientId = requireEnv("GITHUB_CLIENT_ID");
 90→  const githubClientSecret = requireEnv("GITHUB_CLIENT_SECRET");
 91→  const anthropicApiUrl = optionalEnv("ANTHROPIC_API_URL") ?? "https://api.anthropic.com";
 92→  const anthropicApiKey = optionalEnv("ANTHROPIC_API_KEY");
 93→
 94→  const openRouterReasoning = inferenceProvider === "openrouter"
 95→    ? parseOpenRouterReasoning()
 96→    : undefined;
 97→
 98→  const selfHosted = parseBooleanEnv("SELF_HOSTED");
 99→  const worktreeManagerEnabled = parseBooleanEnv("WORKTREE_MANAGER_ENABLED");
100→  const orchestratorMockAgent = parseBooleanEnv("ORCHESTRATOR_MOCK_AGENT");
101→  const internalWebhookSecret = optionalEnv("INTERNAL_WEBHOOK_SECRET");
102→  const toolEncryptionKey = optionalEnv("TOOL_ENCRYPTION_KEY");
103→  const baseUrl = optionalEnv("BRAIN_BASE_URL") ?? `http://localhost:${port}`;
104→
105→  const adminEmail = selfHosted
106→    ? requireSelfHostedEnv("ADMIN_EMAIL")
107→    : undefined;
108→  const adminPassword = selfHosted
109→    ? requireSelfHostedEnv("ADMIN_PASSWORD")
110→    : undefined;
111→
112→  return {
113→    inferenceProvider,
114→    ...(openRouterApiKey ? { openRouterApiKey } : {}),
115→    ...(ollamaBaseUrl ? { ollamaBaseUrl } : {}),
116→    chatAgentModelId,
117→    extractionModelId,
118→    pmAgentModelId,
119→    analyticsAgentModelId,
120→    extractionStoreThreshold,
121→    extractionDisplayThreshold,
122→    ...(openRouterReasoning ? { openRouterReasoning } : {}),
123→    surrealUrl,
124→    surrealUsername,
125→    surrealPassword,
126→    surrealNamespace,
127→    surrealDatabase,
128→    port,
129→    observerModelId,
130→    scorerModelId,
131→    ...(githubWebhookSecret ? { githubWebhookSecret } : {}),
132→    betterAuthSecret,
133→    betterAuthUrl,
134→    githubClientId,
135→    githubClientSecret,
136→    anthropicApiUrl,
137→    ...(anthropicApiKey ? { anthropicApiKey } : {}),
138→    selfHosted,
139→    ...(adminEmail ? { adminEmail } : {}),
140→    ...(adminPassword ? { adminPassword } : {}),
141→    worktreeManagerEnabled,
142→    orchestratorMockAgent,
143→    ...(internalWebhookSecret ? { internalWebhookSecret } : {}),
144→    ...(toolEncryptionKey ? { toolEncryptionKey } : {}),
145→    baseUrl,
146→  };
147→}
148→
149→function optionalEnv(name: string): string | undefined {
150→  const value = Bun.env[name]?.trim();
151→  if (!value) return undefined;
152→  return value;
153→}
154→
155→function requireEnv(name: string): string {
156→  const value = Bun.env[name];
157→  if (!value || value.trim().length === 0) {
158→    throw new Error(`${name} is required`);
159→  }
160→
161→  return value;
162→}
163→
164→function parsePositiveInteger(value: string, envName: string): number {
165→  const parsed = Number(value);
166→  if (!Number.isInteger(parsed) || parsed < 1) {
167→    throw new Error(`${envName} must be a positive integer`);
168→  }
169→  return parsed;
170→}
171→
172→function parseUnitInterval(value: string, envName: string): number {
173→  const parsed = Number(value);
174→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
175→    throw new Error(`${envName} must be a number between 0 and 1`);
176→  }
177→
178→  return parsed;
179→}
180→
181→function parseInferenceProvider(): InferenceProvider {
182→  const value = Bun.env.INFERENCE_PROVIDER?.trim().toLowerCase();
183→  if (!value || value === "openrouter") return "openrouter";
184→  if (value === "ollama") return "ollama";
185→  throw new Error("INFERENCE_PROVIDER must be one of: openrouter, ollama");
186→}
187→
188→function parseBooleanEnv(name: string): boolean {
189→  const value = Bun.env[name]?.trim().toLowerCase();
190→  return value === "true";
191→}
192→
193→function requireSelfHostedEnv(name: string): string {
194→  const value = Bun.env[name]?.trim();
195→  if (!value) {
196→    throw new Error(`${name} is required when SELF_HOSTED=true`);
197→  }
198→  return value;
199→}
200→
201→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
202→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
203→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
204→
205→  if (!effortValue && !maxTokensValue) {
206→    return undefined;
207→  }
208→
209→  const reasoning: OpenRouterReasoningOptions = {};
210→
211→  if (effortValue) {
212→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
213→
214→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
215→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
216→    }
217→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
218→  }
219→
220→  if (maxTokensValue) {
221→    const parsed = Number(maxTokensValue);
222→    if (!Number.isFinite(parsed) || parsed < 1) {
223→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
224→    }
225→    reasoning.max_tokens = parsed;
226→  }
227→
228→  return reasoning;
229→}
