 129→
 130→export function createServerRouteHandlers(deps: ServerDependencies) {
 131→  async function handleCreateServer(
 132→    workspaceId: string,
 133→    request: Request,
 134→  ): Promise<Response> {
 135→    let workspaceRecord: RecordId<"workspace", string>;
 136→    try {
 137→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 138→    } catch (error) {
 139→      if (error instanceof HttpError) {
 140→        return jsonError(error.message, error.status);
 141→      }
 142→      log.error("mcp-server.create", "Failed to resolve workspace", error, { workspaceId });
 143→      return jsonError("internal error", 500);
 144→    }
 145→
 146→    let body: CreateMcpServerInput;
 147→    try {
 148→      body = await request.json() as CreateMcpServerInput;
 149→    } catch {
 150→      return jsonError("invalid JSON body", 400);
 151→    }
 152→
 153→    // Validate name
 154→    if (!body.name || typeof body.name !== "string" || body.name.trim().length === 0) {
 155→      return jsonError("name is required", 400);
 156→    }
 157→
 158→    // Validate URL
 159→    const urlString = body.url ?? "";
 160→    const urlValidation = validateMcpServerUrl(urlString);
 161→    if (!urlValidation.ok) {
 162→      return jsonError(urlValidation.error, 400);
 163→    }
 164→
 165→    // Validate transport (default to streamable-http)
 166→    const transport = body.transport ?? "streamable-http";
 167→    const transportValidation = validateMcpServerTransport(transport);
 168→    if (!transportValidation.ok) {
 169→      return jsonError(transportValidation.error, 400);
 170→    }
 171→
 172→    // Validate provider link if specified
 173→    let providerRecord: RecordId<"credential_provider", string> | undefined;
 174→    let providerName: string | undefined;
 175→    if (body.provider_id) {
 176→      const provider = await getProviderById(deps.surreal, body.provider_id);
 177→      if (!provider) {
 178→        return jsonError("Credential provider not found", 404);
 179→      }
 180→      providerRecord = new RecordId("credential_provider", body.provider_id);
 181→      providerName = (provider as unknown as { display_name?: string }).display_name;
 182→    }
 183→
 184→    // Validate auth_mode
 185→    const authMode = body.auth_mode ?? "none";
 186→    if (!VALID_AUTH_MODES.has(authMode)) {
 187→      return jsonError(`Invalid auth_mode: must be one of none, static_headers, oauth, provider`, 400);
 188→    }
 189→
 190→    // Encrypt static headers if provided
 191→    let encryptedHeaders: EncryptedHeaderEntry[] | undefined;
 192→    if (authMode === "static_headers") {
 193→      const encryptionKey = deps.config.toolEncryptionKey;
 194→      if (!encryptionKey) {
 195→        log.error("mcp-server.create", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
 196→        return jsonError("Server encryption not configured", 500);
 197→      }
 198→      if (!Array.isArray(body.static_headers) || body.static_headers.length === 0) {
 199→        return jsonError("static_headers required when auth_mode is static_headers", 400);
 200→      }
 201→      // Validate header entries before encryption
 202→      for (const header of body.static_headers) {
 203→        if (!header.name || !header.value) {
 204→          return jsonError("Each static header must have name and value", 400);
 205→        }
 206→      }
 207→      const headerValidation = validateHeaders(
 208→        body.static_headers as Array<{ name: string; value: string }>,
 209→      );
 210→      if (!headerValidation.ok) {
 211→        return jsonError(headerValidation.error, 400);
 212→      }
 213→      encryptedHeaders = encryptHeaders(
 214→        body.static_headers as Array<{ name: string; value: string }>,
 215→        encryptionKey,
 216→      );
 217→    }
 218→
 219→    // Check duplicate name
 220→    const duplicate = await serverNameExists(deps.surreal, workspaceRecord, body.name);
 221→    if (duplicate) {
 222→      return jsonError(`MCP server "${body.name}" already exists in this workspace`, 409);
 223→    }
 224→
 225→    // OAuth pre-flight: probe the MCP server for OAuth metadata BEFORE creating
 226→    // the server record. If the auth server doesn't support dynamic client
 227→    // registration, fail early so the user can choose a different auth mode.
 228→    if (authMode === "oauth") {
 229→      const preFlightError = await checkOAuthViability(urlString);
 230→      if (preFlightError) {
 231→        return jsonError(
 232→          `${preFlightError} Use "Static Headers" auth mode with an Authorization header instead.`,
 233→          422,
 234→        );
 235→      }
 236→    }
 237→
 238→    // Create server
 239→    const row = await createMcpServer(deps.surreal, workspaceRecord, {
 240→      name: body.name,
 241→      url: urlString,
 242→      transport,
 243→      authMode,
 244→      staticHeaders: encryptedHeaders,
 245→      providerRecord,
 246→    });
 247→
 248→    const response = toMcpServerResponse(row, providerName) as Record<string, unknown>;
 249→
 250→    // OAuth auto-discovery: create/find provider, register as dynamic client,
 251→    // then generate the authorization URL so the frontend can redirect.
 252→    if (authMode === "oauth") {
 253→      const authResult = await autoDiscoverAndAuthorize(row, workspaceRecord);
 254→      if (authResult?.authorizationUrl) {
 255→        response.authorization_url = authResult.authorizationUrl;
 256→      }
 257→    }
 258→
 259→    return jsonResponse(response, 201);
 260→  }
 261→
 262→  /**
 263→   * Pre-flight check: can this MCP server's OAuth flow actually work?
 264→   * Probes for OAuth metadata and checks if dynamic client registration
 265→   * is available. Returns an error message if OAuth is not viable,
 266→   * or undefined if it can proceed.
 267→   */
 268→  async function checkOAuthViability(mcpServerUrl: string): Promise<string | undefined> {
 269→    try {
 270→      const config = await discoverAuth(mcpServerUrl);
 271→      if (!config) {
 272→        return "No OAuth metadata found at this server URL.";
 273→      }
 274→      if (!config.registrationEndpoint) {
 275→        return "The authorization server does not support dynamic client registration.";
 276→      }
 277→      return undefined;
 278→    } catch (error) {
 279→      return `OAuth discovery failed: ${error instanceof Error ? error.message : "unknown error"}`;
 280→    }
 281→  }
 282→
 283→  /**
 284→   * Auto-discover OAuth metadata from an MCP server and generate an authorization URL.
 285→   * Returns { authorizationUrl } on success, { error } when OAuth cannot proceed,
 286→   * or undefined when discovery finds no OAuth metadata at all.
 287→   */
 288→  async function autoDiscoverAndAuthorize(
 289→    server: McpServerRow,
 290→    workspaceRecord: RecordId<"workspace", string>,
 291→  ): Promise<{ authorizationUrl: string; error?: undefined } | { authorizationUrl?: undefined; error: string } | undefined> {
 292→    try {
 293→      const config = await discoverAuth(server.url);
 294→      if (!config) return undefined;
 295→
 296→      // Find or create credential_provider
 297→      const existingProvider = await findProviderByDiscoverySource(
 298→        deps.surreal,
 299→        workspaceRecord,
 300→        server.url,
 301→      );
 302→      const providerRecord = existingProvider ?? await createProvider(
 303→        deps.surreal,
 304→        workspaceRecord,
 305→        {
 306→          name: new URL(config.authServerUrl).hostname,
 307→          display_name: new URL(config.authServerUrl).hostname,
 308→          auth_method: "oauth2",
 309→          authorization_url: config.authorizationEndpoint,
 310→          token_url: config.tokenEndpoint,
 311→          discovery_source: server.url,
 312→          ...(config.scopesSupported ? { scopes: config.scopesSupported } : {}),
 313→        },
 314→      );
 315→
 316→      // Track client_id: from existing provider or dynamic registration
 317→      let clientId: string | undefined = existingProvider?.client_id;
 318→
 319→      const wsId = workspaceRecord.id as string;
 320→
 321→      // Dynamic client registration (RFC 7591) — only for newly created providers
 322→      if (config.registrationEndpoint && !existingProvider) {
 323→        try {
 324→          const redirectUri = `${deps.config.baseUrl}/api/workspaces/${wsId}/mcp-servers/oauth/callback`;
 325→          const registrationResult = await registerDynamicClient(
 326→            config.registrationEndpoint,
 327→            {
 328→              client_name: "Brain",
 329→              redirect_uris: [redirectUri],
 330→              grant_types: ["authorization_code"],
 331→              response_types: ["code"],
 332→              token_endpoint_auth_method: "none",
 333→            },
 334→          );
 335→
 336→          clientId = registrationResult.client_id;
 337→
 338→          const encryptionKey = deps.config.toolEncryptionKey;
 339→          const clientSecretEncrypted = registrationResult.client_secret && encryptionKey
 340→            ? encryptSecret(registrationResult.client_secret, encryptionKey)
 341→            : undefined;
 342→
 343→          await updateProviderClientRegistration(
 344→            deps.surreal,
 345→            providerRecord.id,
 346→            registrationResult.client_id,
 347→            clientSecretEncrypted,
 348→          );
 349→        } catch (regError) {
 350→          log.error("mcp-server.auto-discover", "Dynamic client registration failed", regError, {
 351→            serverId: server.id.id as string,
 352→          });
 353→        }
 354→      }
 355→
 356→      // Link mcp_server to provider
 357→      await updateMcpServerProvider(deps.surreal, server.id, providerRecord.id);
 358→
 359→      // No client_id means the auth server doesn't support dynamic registration
 360→      // and no client_id was pre-configured. User should use static_headers instead.
 361→      if (!clientId) {
 362→        log.error("mcp-server.auto-discover", "No client_id available — authorization server does not support dynamic client registration", undefined, {
 363→          serverId: server.id.id as string,
 364→          authServer: config.authServerUrl,
 365→        });
 366→        return { error: "The authorization server does not support dynamic client registration." };
 367→      }
 368→
 369→      // Generate PKCE + authorization URL
 370→      const pkce = await generatePkce();
 371→      const state = crypto.randomUUID();
 372→
 373→      await storePendingOAuthState(deps.surreal, server.id, pkce.codeVerifier, state);
 374→
 375→      const redirectUri = `${deps.config.baseUrl}/api/workspaces/${wsId}/mcp-servers/oauth/callback`;
 376→      const scopes = existingProvider?.scopes ?? config.scopesSupported;
 377→
 378→      const authorizationParams: AuthorizationParams = {
 379→        authorizationEndpoint: config.authorizationEndpoint,
 380→        clientId,
 381→        redirectUri,
 382→        codeChallenge: pkce.codeChallenge,
 383→        state,
 384→        resource: server.url,
 385→        scope: scopes?.join(" "),
 386→      };
 387→
 388→      return { authorizationUrl: buildAuthorizationUrl(authorizationParams) };
 389→    } catch (error) {
 390→      log.error("mcp-server.auto-discover", "OAuth auto-discovery failed", error, {
 391→        serverId: server.id.id as string,
 392→      });
 393→      return { error: `OAuth discovery failed: ${error instanceof Error ? error.message : "unknown error"}` };
 394→    }
 395→  }
