 397→  async function handleListServers(
 398→    workspaceId: string,
 399→    _request: Request,
 400→  ): Promise<Response> {
 401→    let workspaceRecord: RecordId<"workspace", string>;
 402→    try {
 403→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 404→    } catch (error) {
 405→      if (error instanceof HttpError) {
 406→        return jsonError(error.message, error.status);
 407→      }
 408→      log.error("mcp-server.list", "Failed to resolve workspace", error, { workspaceId });
 409→      return jsonError("internal error", 500);
 410→    }
 411→
