 560→  async function handleUpdateHeaders(
 561→    workspaceId: string,
 562→    serverId: string,
 563→    request: Request,
 564→  ): Promise<Response> {
 565→    let workspaceRecord: RecordId<"workspace", string>;
 566→    try {
 567→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 568→    } catch (error) {
 569→      if (error instanceof HttpError) {
 570→        return jsonError(error.message, error.status);
 571→      }
 572→      log.error("mcp-server.update-headers", "Failed to resolve workspace", error, { workspaceId });
 573→      return jsonError("internal error", 500);
 574→    }
 575→
 576→    let body: { headers?: Array<{ name?: string; value?: string }> };
 577→    try {
 578→      body = await request.json() as { headers?: Array<{ name?: string; value?: string }> };
 579→    } catch {
 580→      return jsonError("invalid JSON body", 400);
 581→    }
 582→
 583→    if (!Array.isArray(body.headers)) {
 584→      return jsonError("headers array is required", 400);
 585→    }
 586→
 587→    const serverRecord = new RecordId("mcp_server", serverId);
 588→
 589→    // Empty headers array = clear all headers and reset auth_mode to "none"
 590→    if (body.headers.length === 0) {
 591→      const clearedRow = await clearMcpServerHeaders(
 592→        deps.surreal,
 593→        serverRecord,
 594→        workspaceRecord,
 595→      );
 596→
 597→      if (!clearedRow) {
 598→        return jsonError("MCP server not found", 404);
 599→      }
 600→
 601→      return jsonResponse(toMcpServerResponse(clearedRow), 200);
 602→    }
 603→
 604→    // Validate each header entry
 605→    for (const header of body.headers) {
 606→      if (!header.name || !header.value) {
 607→        return jsonError("Each header must have name and value", 400);
 608→      }
 609→    }
 610→    const headerValidation = validateHeaders(
 611→      body.headers as Array<{ name: string; value: string }>,
 612→    );
 613→    if (!headerValidation.ok) {
 614→      return jsonError(headerValidation.error, 400);
 615→    }
 616→
 617→    const encryptionKey = deps.config.toolEncryptionKey;
 618→    if (!encryptionKey) {
 619→      log.error("mcp-server.update-headers", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
 620→      return jsonError("Server encryption not configured", 500);
 621→    }
 622→
 623→    const encryptedHeaders = encryptHeaders(
 624→      body.headers as Array<{ name: string; value: string }>,
 625→      encryptionKey,
 626→    );
 627→
 628→    const updatedRow = await updateMcpServerHeaders(
 629→      deps.surreal,
 630→      serverRecord,
 631→      workspaceRecord,
 632→      encryptedHeaders,
 633→    );
 634→
 635→    if (!updatedRow) {
 636→      return jsonError("MCP server not found", 404);
 637→    }
 638→
 639→    return jsonResponse(toMcpServerResponse(updatedRow), 200);
 640→  }
