 642→  async function handleDiscoverAuth(
 643→    workspaceId: string,
 644→    serverId: string,
 645→    _request: Request,
 646→  ): Promise<Response> {
 647→    const resolved = await resolveServer(workspaceId, serverId);
 648→    if ("error" in resolved) return resolved.error;
 649→
 650→    const server = resolved.server;
 651→
 652→    try {
 653→      const config = await discoverAuth(server.url);
 654→
 655→      if (!config) {
 656→        const response: DiscoverAuthResponse = {
 657→          discovered: false,
 658→          error: "No OAuth metadata found at the MCP server URL",
 659→        };
 660→        return jsonResponse(response, 200);
 661→      }
 662→
 663→      // Find or create credential_provider from discovery (dedup by discovery_source)
 664→      const authServerHostname = new URL(config.authServerUrl).hostname;
 665→      const existingProvider = await findProviderByDiscoverySource(
 666→        deps.surreal,
 667→        server.workspace,
 668→        server.url,
 669→      );
 670→      const providerRecord = existingProvider ?? await createProvider(
 671→        deps.surreal,
 672→        server.workspace,
 673→        {
 674→          name: authServerHostname,
 675→          display_name: authServerHostname,
 676→          auth_method: "oauth2",
 677→          authorization_url: config.authorizationEndpoint,
 678→          token_url: config.tokenEndpoint,
 679→          discovery_source: server.url,
 680→          ...(config.scopesSupported ? { scopes: config.scopesSupported } : {}),
 681→        },
 682→      );
 683→
 684→      // Dynamic client registration (RFC 7591) — only for newly created providers
 685→      if (config.registrationEndpoint && !existingProvider) {
 686→        try {
 687→          const redirectUri = `${deps.config.baseUrl}/api/workspaces/${workspaceId}/mcp-servers/oauth/callback`;
 688→
 689→          const registrationResult = await registerDynamicClient(
 690→            config.registrationEndpoint,
 691→            {
 692→              client_name: "Brain",
 693→              redirect_uris: [redirectUri],
 694→              grant_types: ["authorization_code"],
 695→              response_types: ["code"],
 696→              token_endpoint_auth_method: "none",
 697→            },
 698→          );
 699→
 700→          const encryptionKey = deps.config.toolEncryptionKey;
 701→          const clientSecretEncrypted = registrationResult.client_secret && encryptionKey
 702→            ? encryptSecret(registrationResult.client_secret, encryptionKey)
 703→            : undefined;
 704→
 705→          await updateProviderClientRegistration(
 706→            deps.surreal,
 707→            providerRecord.id,
 708→            registrationResult.client_id,
 709→            clientSecretEncrypted,
 710→          );
 711→        } catch (regError) {
 712→          log.error("mcp-server.discover-auth", "Dynamic client registration failed", regError, { serverId: server.id.id as string });
 713→          // Non-fatal: proceed without dynamic registration
 714→        }
 715→      }
 716→
 717→      // Link mcp_server to the new provider
 718→      await updateMcpServerProvider(
 719→        deps.surreal,
 720→        server.id,
 721→        providerRecord.id,
 722→      );
 723→
 724→      const response: DiscoverAuthResponse = {
 725→        discovered: true,
 726→        auth_server: config.authServerUrl,
 727→        authorization_endpoint: config.authorizationEndpoint,
 728→        token_endpoint: config.tokenEndpoint,
 729→        scopes_supported: config.scopesSupported,
 730→        supports_dynamic_registration: config.registrationEndpoint !== undefined,
 731→        provider_id: providerRecord.id.id as string,
 732→      };
 733→
 734→      return jsonResponse(response, 200);
 735→    } catch (error) {
 736→      log.error("mcp-server.discover-auth", "OAuth discovery failed", error, { serverId });
 737→      return jsonError(
 738→        `OAuth discovery failed: ${error instanceof Error ? error.message : "unknown error"}`,
 739→        502,
 740→      );
 741→    }
 742→  }
