 744→  async function handleAuthorize(
 745→    workspaceId: string,
 746→    serverId: string,
 747→    _request: Request,
 748→  ): Promise<Response> {
 749→    const resolved = await resolveServer(workspaceId, serverId);
 750→    if ("error" in resolved) return resolved.error;
 751→
 752→    const server = resolved.server;
 753→
 754→    // Server must have a linked credential_provider (from discover-auth)
 755→    if (!server.provider) {
 756→      return jsonError("MCP server has no linked credential provider. Run discover-auth first.", 400);
 757→    }
 758→
 759→    const provider = await getProviderById(deps.surreal, server.provider.id as string);
 760→    if (!provider) {
 761→      return jsonError("Linked credential provider not found", 404);
 762→    }
 763→
 764→    const providerRecord = provider as unknown as {
 765→      authorization_url?: string;
 766→      client_id?: string;
 767→      scopes?: string[];
 768→    };
 769→
 770→    if (!providerRecord.authorization_url) {
 771→      return jsonError("Provider missing authorization_url", 400);
 772→    }
 773→
 774→    // Generate PKCE pair and random state
 775→    const pkce = await generatePkce();
 776→    const state = crypto.randomUUID();
 777→
 778→    // Store pending state on the mcp_server record (no module-level singletons)
 779→    await storePendingOAuthState(
 780→      deps.surreal,
 781→      server.id,
 782→      pkce.codeVerifier,
 783→      state,
 784→    );
 785→
 786→    // Build the redirect_uri (Brain's OAuth callback)
 787→    const redirectUri = `${deps.config.baseUrl}/api/workspaces/${workspaceId}/mcp-servers/oauth/callback`;
 788→
 789→    const clientId = providerRecord.client_id;
 790→    if (!clientId) {
 791→      return jsonError(
 792→        "Provider has no client_id. The authorization server may not support dynamic client registration. Use static_headers auth mode with a pre-issued token instead.",
 793→        400,
 794→      );
 795→    }
 796→
 797→    // Build authorization URL with PKCE and resource parameter
 798→    const authorizationParams: AuthorizationParams = {
 799→      authorizationEndpoint: providerRecord.authorization_url,
 800→      clientId,
 801→      redirectUri,
 802→      codeChallenge: pkce.codeChallenge,
 803→      state,
 804→      resource: server.url,
 805→      scope: providerRecord.scopes?.join(" "),
 806→    };
 807→
 808→    const redirectUrl = buildAuthorizationUrl(authorizationParams);
 809→
 810→    return jsonResponse({ redirect_url: redirectUrl, state }, 200);
 811→  }
