 813→  async function handleOAuthCallback(
 814→    workspaceId: string,
 815→    request: Request,
 816→  ): Promise<Response> {
 817→    let workspaceRecord: RecordId<"workspace", string>;
 818→    try {
 819→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 820→    } catch (error) {
 821→      if (error instanceof HttpError) {
 822→        return jsonError(error.message, error.status);
 823→      }
 824→      log.error("mcp-server.oauth-callback", "Failed to resolve workspace", error, { workspaceId });
 825→      return jsonError("internal error", 500);
 826→    }
 827→
 828→    // Parse code + state from query params (GET redirect from OAuth provider)
 829→    // or request body (POST from frontend) for backwards compat
 830→    let code: string | undefined;
 831→    let state: string | undefined;
 832→
 833→    const url = new URL(request.url);
 834→    if (url.searchParams.has("code")) {
 835→      code = url.searchParams.get("code") ?? undefined;
 836→      state = url.searchParams.get("state") ?? undefined;
 837→    } else {
 838→      try {
 839→        const body = await request.json() as { code?: string; state?: string };
 840→        code = body.code;
 841→        state = body.state;
 842→      } catch {
 843→        return jsonError("invalid request", 400);
 844→      }
 845→    }
 846→
 847→    if (!code || typeof code !== "string") {
 848→      return jsonError("code is required", 400);
 849→    }
 850→    if (!state || typeof state !== "string") {
 851→      return jsonError("state is required", 400);
 852→    }
 853→
 854→    // Find the mcp_server that has this pending state
 855→    const server = await findServerByPendingState(deps.surreal, workspaceRecord, state);
 856→    if (!server) {
 857→      return jsonError("No pending authorization found for the provided state", 404);
 858→    }
 859→
 860→    if (!server.pending_pkce_verifier) {
 861→      return jsonError("Server missing PKCE code_verifier", 400);
 862→    }
 863→
 864→    // Load the linked credential_provider for token_endpoint
 865→    if (!server.provider) {
 866→      return jsonError("Server has no linked credential provider", 400);
 867→    }
 868→
 869→    const provider = await getProviderById(deps.surreal, server.provider.id as string);
 870→    if (!provider) {
 871→      return jsonError("Linked credential provider not found", 404);
 872→    }
 873→
 874→    const providerRecord = provider as unknown as {
 875→      token_url?: string;
 876→      client_id?: string;
 877→    };
 878→
 879→    if (!providerRecord.token_url) {
 880→      return jsonError("Provider missing token_url", 400);
 881→    }
 882→
 883→    // Build redirect_uri (must match the one used during authorize)
 884→    const redirectUri = `${deps.config.baseUrl}/api/workspaces/${workspaceId}/mcp-servers/oauth/callback`;
 885→
 886→    const clientId = providerRecord.client_id;
 887→    if (!clientId) {
 888→      const msg = "Provider has no client_id configured";
 889→      if (request.method === "GET") {
 890→        return Response.redirect(
 891→          `${deps.config.baseUrl}/tools?tab=servers&oauth=error`,
 892→          302,
 893→        );
 894→      }
 895→      return jsonError(msg, 400);
 896→    }
 897→
 898→    try {
 899→      // Exchange the authorization code for tokens using PKCE
 900→      const tokenResult = await exchangeCode({
 901→        tokenEndpoint: providerRecord.token_url,
 902→        code,
 903→        redirectUri,
 904→        codeVerifier: server.pending_pkce_verifier,
 905→        clientId,
 906→      });
 907→
 908→      // Encrypt tokens before storage
 909→      const encryptionKey = deps.config.toolEncryptionKey;
 910→      if (encryptionKey) {
 911→        // Find workspace owner identity for the connected_account
 912→        const ownerIdentity = await findWorkspaceOwnerIdentity(deps.surreal, workspaceRecord);
 913→        if (ownerIdentity) {
 914→          const accountContent: Record<string, unknown> = {
 915→            identity: ownerIdentity,
 916→            provider: server.provider,
 917→            workspace: workspaceRecord,
 918→            status: "active",
 919→            access_token_encrypted: encryptSecret(tokenResult.access_token, encryptionKey),
 920→          };
 921→
 922→          if (tokenResult.refresh_token) {
 923→            accountContent.refresh_token_encrypted = encryptSecret(tokenResult.refresh_token, encryptionKey);
 924→          }
 925→
 926→          if (tokenResult.expires_in) {
 927→            accountContent.token_expires_at = new Date(Date.now() + tokenResult.expires_in * 1000);
 928→          }
 929→
 930→          if (tokenResult.scope) {
 931→            accountContent.scopes = tokenResult.scope.split(" ");
 932→          }
 933→
 934→          const account = await createConnectedAccount(deps.surreal, accountContent);
 935→
 936→          // Link mcp_server to the new connected_account
 937→          await updateMcpServerOAuthAccount(deps.surreal, server.id, account.id);
 938→        }
 939→      }
 940→
 941→      // Clear pending PKCE state and mark server as authenticated
 942→      await clearPendingOAuthState(deps.surreal, server.id);
 943→      await updateMcpServerStatus(deps.surreal, server.id, "ok");
 944→
 945→      // GET = browser redirect from OAuth provider → redirect back to UI
 946→      // POST = programmatic call → return JSON
 947→      if (request.method === "GET") {
 948→        return Response.redirect(
 949→          `${deps.config.baseUrl}/tools?tab=servers&oauth=success`,
 950→          302,
 951→        );
 952→      }
 953→      return jsonResponse(tokenResult, 200);
 954→    } catch (error) {
 955→      log.error("mcp-server.oauth-callback", "Token exchange failed", error, { workspaceId });
 956→      if (request.method === "GET") {
 957→        return Response.redirect(
 958→          `${deps.config.baseUrl}/tools?tab=servers&oauth=error`,
 959→          302,
 960→        );
 961→      }
 962→      return jsonError(
 963→        `Token exchange failed: ${error instanceof Error ? error.message : "unknown error"}`,
 964→        502,
 965→      );
 966→    }
 967→  }
