230→/**
231→ * Run full discovery: connect to MCP server, list tools, diff against
232→ * existing records, optionally apply changes.
233→ *
234→ * Returns a DiscoveryResult with per-tool sync details + summary counts.
235→ */
236→export async function discoverTools(
237→  deps: DiscoveryDeps,
238→  server: McpServerRecord,
239→  options: DiscoverToolsOptions,
240→): Promise<SyncApplyResult> {
241→  const serverRecord = server.id;
242→
243→  // 1. Resolve auth headers for the server, then connect
244→  const authHeaders = deps.toolEncryptionKey
245→    ? await resolveAuthForMcpServer(server, deps.toolEncryptionKey, {
246→        surreal: deps.surreal,
247→        toolEncryptionKey: deps.toolEncryptionKey,
248→      })
249→    : {};
250→
251→  const connection = await deps.mcpClientFactory.connect(
252→    server.url,
253→    server.transport as McpTransport,
254→    Object.keys(authHeaders).length > 0 ? authHeaders : undefined,
255→  );
256→
257→  let toolListResult: ToolListResult;
258→  try {
259→    toolListResult = await deps.mcpClientFactory.fetchToolList(
260→      connection.client,
261→    );
262→  } finally {
263→    await deps.mcpClientFactory.disconnect(connection.client).catch(() => {});
264→  }
265→
266→  // 2. Convert to RemoteTool shape
267→  const remoteTools = toRemoteTools(toolListResult);
268→
269→  // 3. Fetch existing local tools for this server
270→  const existingTools = await fetchExistingToolsForServer(
271→    deps.surreal,
272→    serverRecord,
273→  );
274→
275→  // 4. Compute sync actions
276→  let syncDetails = computeSyncActions(remoteTools, existingTools);
277→
278→  // 5. Apply selection filter
279→  syncDetails = filterBySelection(syncDetails, options.selectedTools);
280→
281→  // 6. Count actions
282→  const counts = countActions(syncDetails);
283→
284→  // 7. If not dry-run, apply changes to DB
285→  if (!options.dryRun) {
286→    await applySyncActions(deps.surreal, server, syncDetails);
287→  }
288→
289→  return {
290→    ...counts,
291→    tools: syncDetails,
292→  };
293→}
294→
295→/**
296→ * Count actions in a list of sync details.
297→ */
298→function countActions(tools: ToolSyncDetail[]): {
299→  created: number;
300→  updated: number;
301→  disabled: number;
302→  unchanged: number;
303→} {
304→  let created = 0;
305→  let updated = 0;
306→  let disabled = 0;
307→  let unchanged = 0;
308→
309→  for (const tool of tools) {
310→    switch (tool.action) {
311→      case "create":
312→        created++;
313→        break;
314→      case "update":
315→        updated++;
316→        break;
317→      case "disable":
318→        disabled++;
319→        break;
320→      case "unchanged":
321→        unchanged++;
322→        break;
323→    }
324→  }
325→
326→  return { created, updated, disabled, unchanged };
327→}
328→
329→/**
330→ * Apply sync actions to SurrealDB: create/update/disable tools,
331→ * update server metadata.
332→ */
333→async function applySyncActions(
334→  surreal: Surreal,
335→  server: McpServerRecord,
336→  syncDetails: ToolSyncDetail[],
337→): Promise<void> {
338→  const serverRecord = server.id;
339→  const workspaceRecord = server.workspace;
340→
341→  for (const tool of syncDetails) {
342→    switch (tool.action) {
343→      case "create": {
344→        const toolId = `tool-${crypto.randomUUID()}`;
345→        const toolRecord = new RecordId("mcp_tool", toolId);
346→        await surreal.query(`CREATE $tool CONTENT $content;`, {
347→          tool: toolRecord,
348→          content: {
349→            name: tool.name,
350→            description: tool.description,
351→            input_schema: tool.input_schema,
352→            output_schema: tool.output_schema,
353→            risk_level: tool.risk_level,
354→            toolkit: deriveToolkit(tool.name),
355→            status: "active",
356→            workspace: workspaceRecord,
357→            source_server: serverRecord,
358→            created_at: new Date(),
359→          },
360→        });
361→        break;
362→      }
363→      case "update": {
364→        await surreal.query(
365→          `UPDATE mcp_tool SET
366→             description = $description,
367→             input_schema = $inputSchema,
368→             output_schema = $outputSchema,
369→             risk_level = $riskLevel
370→           WHERE name = $name AND source_server = $server;`,
371→          {
372→            description: tool.description,
373→            inputSchema: tool.input_schema,
374→            outputSchema: tool.output_schema,
375→            riskLevel: tool.risk_level,
376→            name: tool.name,
377→            server: serverRecord,
378→          },
379→        );
380→        break;
381→      }
382→      case "disable": {
383→        await surreal.query(
384→          `UPDATE mcp_tool SET status = "disabled"
385→           WHERE name = $name AND source_server = $server;`,
386→          { name: tool.name, server: serverRecord },
387→        );
388→        break;
389→      }
390→      // "unchanged" -> no DB write needed
391→    }
392→  }
393→
394→  // Update server metadata
395→  const activeToolCount = syncDetails.filter(
396→    (t) => t.action !== "disable",
397→  ).length;
398→
399→  await surreal.query(
400→    `UPDATE $server SET
401→       last_discovery = time::now(),
402→       tool_count = $toolCount;`,
403→    { server: serverRecord, toolCount: activeToolCount },
404→  );
405→}
406→
407→/**
408→ * Derive toolkit name from a tool name.
409→ * Convention: first segment before the dot, or the full name if no dot.
410→ */
411→function deriveToolkit(toolName: string): string {
412→  const dotIndex = toolName.indexOf(".");
413→  return dotIndex > 0 ? toolName.substring(0, dotIndex) : toolName;
414→}
