206→// ---------------------------------------------------------------------------
207→// Add server form validation
208→// ---------------------------------------------------------------------------
209→
210→function isValidHttpUrl(urlString: string): { valid: boolean; error?: string } {
211→  if (urlString.trim() === "") {
212→    return { valid: false, error: "URL is required" };
213→  }
214→  try {
215→    const parsed = new URL(urlString);
216→    if (parsed.protocol !== "http:" && parsed.protocol !== "https:") {
217→      return { valid: false, error: "URL must use http:// or https://" };
218→    }
219→    return { valid: true };
220→  } catch {
221→    return { valid: false, error: "URL must use http:// or https://" };
222→  }
223→}
224→
225→export function validateAddMcpServerForm(
226→  formData: AddMcpServerFormData,
227→  existingNames: string[],
228→): AddMcpServerValidationResult {
229→  const errors: Partial<Record<AddMcpServerFieldName | "static_headers", string>> = {};
230→
231→  // Name validation
232→  if (formData.name.trim() === "") {
233→    errors.name = "Name is required";
234→  } else if (existingNames.includes(formData.name.trim())) {
235→    errors.name = "A server with this name already exists";
236→  }
237→
238→  // URL validation
239→  const urlValidation = isValidHttpUrl(formData.url);
240→  if (!urlValidation.valid) {
241→    errors.url = urlValidation.error;
242→  }
243→
244→  // Static headers validation
245→  if (formData.auth_mode === "static_headers") {
246→    if (formData.static_headers.length === 0) {
247→      errors.static_headers = "At least one header is required";
248→    } else {
249→      const hasEmpty = formData.static_headers.some(
250→        (h) => h.name.trim() === "" || h.value.trim() === "",
251→      );
252→      if (hasEmpty) {
253→        errors.static_headers = "All headers must have a name and value";
254→      }
255→    }
256→  }
257→
258→  // Provider validation
259→  if (formData.auth_mode === "provider" && !formData.credentialProviderId) {
260→    errors.credentialProviderId = "Select a credential provider";
261→  }
262→
263→  return {
264→    isValid: Object.keys(errors).length === 0,
265→    errors,
266→  };
267→}
