 80→/**
 81→ * Create the appropriate MCP transport based on transport type.
 82→ * Injects auth headers into the transport's requestInit.
 83→ */
 84→export function createTransport(
 85→  url: string,
 86→  transportType: McpTransport,
 87→  headers?: Record<string, string>,
 88→): Transport {
 89→  const parsedUrl = new URL(url);
 90→  const authHeaders = buildAuthHeaders(headers);
 91→  const requestInit: RequestInit = {
 92→    headers: authHeaders,
 93→  };
 94→
 95→  switch (transportType) {
 96→    case "sse":
 97→      return new SSEClientTransport(parsedUrl, {
 98→        fetch: createFetchWithHeaders(authHeaders),
 99→        requestInit,
100→      });
101→    case "streamable-http":
102→      return new StreamableHTTPClientTransport(parsedUrl, {
103→        requestInit,
104→      });
105→  }
106→}
