211→/**
212→ * Create a fetch wrapper that injects auth headers into SSE EventSource requests.
213→ * The SSE transport's eventSourceInit.fetch is called for the initial GET request.
214→ */
215→function createFetchWithHeaders(
216→  headers: Record<string, string>,
217→): (input: string | URL | Request, init?: RequestInit) => Promise<Response> {
218→  return (input, init) => {
219→    const mergedHeaders = new Headers(init?.headers);
220→    for (const [key, value] of Object.entries(headers)) {
221→      mergedHeaders.set(key, value);
222→    }
223→    return fetch(input, { ...init, headers: mergedHeaders });
224→  };
225→}
