 48→export function loadServerConfig(): ServerConfig {
 49→  const inferenceProvider = parseInferenceProvider();
 50→
 51→  const openRouterApiKey = inferenceProvider === "openrouter"
 52→    ? requireEnv("OPENROUTER_API_KEY")
 53→    : Bun.env.OPENROUTER_API_KEY?.trim() || undefined;
 54→
 55→  const ollamaBaseUrl = inferenceProvider === "ollama"
 56→    ? (Bun.env.OLLAMA_BASE_URL?.trim() || "http://127.0.0.1:11434")
 57→    : undefined;
 58→
 59→  const extractionStoreThreshold = parseUnitInterval(
 60→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 61→    "EXTRACTION_STORE_THRESHOLD",
 62→  );
 63→
 64→  const extractionDisplayThreshold = parseUnitInterval(
 65→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 66→    "EXTRACTION_DISPLAY_THRESHOLD",
 67→  );
 68→
 69→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 70→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 71→  }
 72→
 73→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 74→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 75→  const pmAgentModelId = optionalEnv("PM_AGENT_MODEL") ?? extractionModelId;
