 80→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 81→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 82→
 83→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 84→  const observerModelId = optionalEnv("OBSERVER_MODEL") ?? extractionModelId;
 85→  const scorerModelId = optionalEnv("SCORER_MODEL") ?? extractionModelId;
 86→  const githubWebhookSecret = optionalEnv("GITHUB_WEBHOOK_SECRET");
 87→  const betterAuthSecret = requireEnv("BETTER_AUTH_SECRET");
 88→  const betterAuthUrl = requireEnv("BETTER_AUTH_URL");
 89→  const githubClientId = requireEnv("GITHUB_CLIENT_ID");
 90→  const githubClientSecret = requireEnv("GITHUB_CLIENT_SECRET");
 91→  const anthropicApiUrl = optionalEnv("ANTHROPIC_API_URL") ?? "https://api.anthropic.com";
 92→  const anthropicApiKey = optionalEnv("ANTHROPIC_API_KEY");
 93→
