149→function optionalEnv(name: string): string | undefined {
150→  const value = Bun.env[name]?.trim();
151→  if (!value) return undefined;
152→  return value;
153→}
154→
155→function requireEnv(name: string): string {
156→  const value = Bun.env[name];
157→  if (!value || value.trim().length === 0) {
158→    throw new Error(`${name} is required`);
159→  }
160→
161→  return value;
162→}
163→
164→function parsePositiveInteger(value: string, envName: string): number {
165→  const parsed = Number(value);
166→  if (!Number.isInteger(parsed) || parsed < 1) {
167→    throw new Error(`${envName} must be a positive integer`);
168→  }
169→  return parsed;
170→}
171→
172→function parseUnitInterval(value: string, envName: string): number {
173→  const parsed = Number(value);
174→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
175→    throw new Error(`${envName} must be a number between 0 and 1`);
176→  }
177→
178→  return parsed;
179→}
