   1→/**
   2→ * HTTP routes for MCP server management.
   3→ *
   4→ * POST   /api/workspaces/:wsId/mcp-servers              (register server)
   5→ * GET    /api/workspaces/:wsId/mcp-servers               (list servers)
   6→ * GET    /api/workspaces/:wsId/mcp-servers/:serverId     (server detail)
   7→ * DELETE /api/workspaces/:wsId/mcp-servers/:serverId     (remove server)
   8→ * POST   /api/workspaces/:wsId/mcp-servers/:serverId/discover  (dry-run discovery)
   9→ * POST   /api/workspaces/:wsId/mcp-servers/:serverId/sync      (apply sync)
  10→ */
  11→import { RecordId } from "surrealdb";
  12→import { HttpError } from "../http/errors";
  13→import { jsonError, jsonResponse } from "../http/response";
  14→import type { ServerDependencies } from "../runtime/types";
  15→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
  16→import {
  17→  validateMcpServerUrl,
  18→  validateMcpServerTransport,
  19→} from "./server-validation";
  20→import {
  21→  serverNameExists,
  22→  createMcpServer,
  23→  listMcpServers,
  24→  getMcpServerById,
  25→  deleteMcpServer,
  26→  updateMcpServerHeaders,
  27→  clearMcpServerHeaders,
  28→  updateMcpServerProvider,
  29→  storePendingOAuthState,
  30→  findServerByPendingState,
  31→  clearPendingOAuthState,
  32→  updateMcpServerOAuthAccount,
  33→  findWorkspaceOwnerIdentity,
  34→  getMcpServerAuthStatus,
  35→  updateMcpServerStatus,
  36→  type McpServerRow,
  37→} from "./server-queries";
  38→import {
  39→  getProviderById,
  40→  createProvider,
  41→  findProviderByDiscoverySource,
  42→  createConnectedAccount,
  43→  updateProviderClientRegistration,
  44→} from "./queries";
  45→import { encryptSecret } from "./encryption";
  46→import { discoverTools } from "./discovery";
  47→import { discoverAuth } from "./auth-discovery";
  48→import { generatePkce, buildAuthorizationUrl, exchangeCode, registerDynamicClient } from "./oauth-flow";
  49→import type { McpServerRecord, EncryptedHeaderEntry, DiscoverAuthResponse, AuthorizationParams } from "./types";
  50→import { encryptHeaders, validateHeaders } from "./static-headers";
  51→import { log } from "../telemetry/logger";
  52→
  53→const VALID_AUTH_MODES: ReadonlySet<string> = new Set(["none", "static_headers", "oauth", "provider"]);
  54→
  55→// ---------------------------------------------------------------------------
  56→// Response mapping -- DB record to API shape
  57→// ---------------------------------------------------------------------------
  58→
  59→type McpServerResponse = {
  60→  id: string;
  61→  name: string;
  62→  url: string;
  63→  transport: string;
  64→  auth_mode: string;
  65→  has_static_headers: boolean;
  66→  tool_count: number;
  67→  last_status?: string;
  68→  last_error?: string;
  69→  last_discovery?: string;
  70→  provider_id?: string;
  71→  provider_name?: string;
  72→  created_at: string;
  73→};
  74→
  75→function toMcpServerResponse(
  76→  row: McpServerRow,
  77→  providerName?: string,
  78→): McpServerResponse {
  79→  const response: McpServerResponse = {
  80→    id: row.id.id as string,
  81→    name: row.name,
  82→    url: row.url,
  83→    transport: row.transport,
  84→    auth_mode: row.auth_mode ?? "none",
  85→    has_static_headers: Array.isArray(row.static_headers) && row.static_headers.length > 0,
  86→    tool_count: row.tool_count,
  87→    created_at: row.created_at instanceof Date
  88→      ? row.created_at.toISOString()
  89→      : String(row.created_at),
  90→  };
  91→
  92→  if (row.last_status) {
  93→    response.last_status = row.last_status;
  94→  }
  95→  if (row.last_error) {
  96→    response.last_error = row.last_error;
  97→  }
  98→  if (row.last_discovery) {
  99→    response.last_discovery = row.last_discovery instanceof Date
 100→      ? row.last_discovery.toISOString()
 101→      : String(row.last_discovery);
 102→  }
 103→  if (row.provider) {
 104→    response.provider_id = row.provider.id as string;
 105→    if (providerName) {
 106→      response.provider_name = providerName;
 107→    }
 108→  }
 109→
 110→  return response;
 111→}
 112→
 113→// ---------------------------------------------------------------------------
 114→// Input type
 115→// ---------------------------------------------------------------------------
 116→
 117→type CreateMcpServerInput = {
 118→  name?: string;
 119→  url?: string;
 120→  transport?: string;
 121→  provider_id?: string;
 122→  auth_mode?: string;
 123→  static_headers?: Array<{ name?: string; value?: string }>;
 124→};
 125→
 126→// ---------------------------------------------------------------------------
 127→// Route handlers
 128→// ---------------------------------------------------------------------------
 129→
 130→export function createServerRouteHandlers(deps: ServerDependencies) {
 131→  async function handleCreateServer(
 132→    workspaceId: string,
 133→    request: Request,
 134→  ): Promise<Response> {
 135→    let workspaceRecord: RecordId<"workspace", string>;
 136→    try {
 137→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 138→    } catch (error) {
 139→      if (error instanceof HttpError) {
 140→        return jsonError(error.message, error.status);
 141→      }
 142→      log.error("mcp-server.create", "Failed to resolve workspace", error, { workspaceId });
 143→      return jsonError("internal error", 500);
 144→    }
 145→
 146→    let body: CreateMcpServerInput;
 147→    try {
 148→      body = await request.json() as CreateMcpServerInput;
 149→    } catch {
 150→      return jsonError("invalid JSON body", 400);
 151→    }
 152→
 153→    // Validate name
 154→    if (!body.name || typeof body.name !== "string" || body.name.trim().length === 0) {
 155→      return jsonError("name is required", 400);
 156→    }
 157→
 158→    // Validate URL
 159→    const urlString = body.url ?? "";
 160→    const urlValidation = validateMcpServerUrl(urlString);
 161→    if (!urlValidation.ok) {
 162→      return jsonError(urlValidation.error, 400);
 163→    }
 164→
 165→    // Validate transport (default to streamable-http)
 166→    const transport = body.transport ?? "streamable-http";
 167→    const transportValidation = validateMcpServerTransport(transport);
 168→    if (!transportValidation.ok) {
 169→      return jsonError(transportValidation.error, 400);
 170→    }
 171→
 172→    // Validate provider link if specified
 173→    let providerRecord: RecordId<"credential_provider", string> | undefined;
 174→    let providerName: string | undefined;
 175→    if (body.provider_id) {
 176→      const provider = await getProviderById(deps.surreal, body.provider_id);
 177→      if (!provider) {
 178→        return jsonError("Credential provider not found", 404);
 179→      }
 180→      providerRecord = new RecordId("credential_provider", body.provider_id);
 181→      providerName = (provider as unknown as { display_name?: string }).display_name;
 182→    }
 183→
 184→    // Validate auth_mode
 185→    const authMode = body.auth_mode ?? "none";
 186→    if (!VALID_AUTH_MODES.has(authMode)) {
 187→      return jsonError(`Invalid auth_mode: must be one of none, static_headers, oauth, provider`, 400);
 188→    }
 189→
 190→    // Encrypt static headers if provided
 191→    let encryptedHeaders: EncryptedHeaderEntry[] | undefined;
 192→    if (authMode === "static_headers") {
 193→      const encryptionKey = deps.config.toolEncryptionKey;
 194→      if (!encryptionKey) {
 195→        log.error("mcp-server.create", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
 196→        return jsonError("Server encryption not configured", 500);
 197→      }
 198→      if (!Array.isArray(body.static_headers) || body.static_headers.length === 0) {
 199→        return jsonError("static_headers required when auth_mode is static_headers", 400);
 200→      }
 201→      // Validate header entries before encryption
 202→      for (const header of body.static_headers) {
 203→        if (!header.name || !header.value) {
 204→          return jsonError("Each static header must have name and value", 400);
 205→        }
 206→      }
 207→      const headerValidation = validateHeaders(
 208→        body.static_headers as Array<{ name: string; value: string }>,
 209→      );
 210→      if (!headerValidation.ok) {
 211→        return jsonError(headerValidation.error, 400);
 212→      }
 213→      encryptedHeaders = encryptHeaders(
 214→        body.static_headers as Array<{ name: string; value: string }>,
 215→        encryptionKey,
 216→      );
 217→    }
 218→
 219→    // Check duplicate name
 220→    const duplicate = await serverNameExists(deps.surreal, workspaceRecord, body.name);
 221→    if (duplicate) {
 222→      return jsonError(`MCP server "${body.name}" already exists in this workspace`, 409);
 223→    }
 224→
 225→    // OAuth pre-flight: probe the MCP server for OAuth metadata BEFORE creating
 226→    // the server record. If the auth server doesn't support dynamic client
 227→    // registration, fail early so the user can choose a different auth mode.
 228→    if (authMode === "oauth") {
 229→      const preFlightError = await checkOAuthViability(urlString);
 230→      if (preFlightError) {
 231→        return jsonError(
 232→          `${preFlightError} Use "Static Headers" auth mode with an Authorization header instead.`,
 233→          422,
 234→        );
 235→      }
 236→    }
 237→
 238→    // Create server
 239→    const row = await createMcpServer(deps.surreal, workspaceRecord, {
 240→      name: body.name,
 241→      url: urlString,
 242→      transport,
 243→      authMode,
 244→      staticHeaders: encryptedHeaders,
 245→      providerRecord,
 246→    });
 247→
 248→    const response = toMcpServerResponse(row, providerName) as Record<string, unknown>;
 249→
 250→    // OAuth auto-discovery: create/find provider, register as dynamic client,
 251→    // then generate the authorization URL so the frontend can redirect.
 252→    if (authMode === "oauth") {
 253→      const authResult = await autoDiscoverAndAuthorize(row, workspaceRecord);
 254→      if (authResult?.authorizationUrl) {
 255→        response.authorization_url = authResult.authorizationUrl;
 256→      }
 257→    } else {
 258→      // Non-OAuth servers can sync tools immediately after creation
 259→      triggerAutoSync(row as unknown as McpServerRecord);
 260→    }
 261→
 262→    return jsonResponse(response, 201);
 263→  }
 264→
 265→  /**
 266→   * Pre-flight check: can this MCP server's OAuth flow actually work?
 267→   * Probes for OAuth metadata and checks if dynamic client registration
 268→   * is available. Returns an error message if OAuth is not viable,
 269→   * or undefined if it can proceed.
 270→   */
 271→  async function checkOAuthViability(mcpServerUrl: string): Promise<string | undefined> {
 272→    try {
 273→      const config = await discoverAuth(mcpServerUrl);
 274→      if (!config) {
 275→        return "No OAuth metadata found at this server URL.";
 276→      }
 277→      if (!config.registrationEndpoint) {
 278→        return "The authorization server does not support dynamic client registration.";
 279→      }
 280→      return undefined;
 281→    } catch (error) {
 282→      return `OAuth discovery failed: ${error instanceof Error ? error.message : "unknown error"}`;
 283→    }
 284→  }
 285→
 286→  /**
 287→   * Auto-discover OAuth metadata from an MCP server and generate an authorization URL.
 288→   * Returns { authorizationUrl } on success, { error } when OAuth cannot proceed,
 289→   * or undefined when discovery finds no OAuth metadata at all.
 290→   */
 291→  async function autoDiscoverAndAuthorize(
 292→    server: McpServerRow,
 293→    workspaceRecord: RecordId<"workspace", string>,
 294→  ): Promise<{ authorizationUrl: string; error?: undefined } | { authorizationUrl?: undefined; error: string } | undefined> {
 295→    try {
 296→      const config = await discoverAuth(server.url);
 297→      if (!config) return undefined;
 298→
 299→      // Find or create credential_provider
 300→      const existingProvider = await findProviderByDiscoverySource(
 301→        deps.surreal,
 302→        workspaceRecord,
 303→        server.url,
 304→      );
 305→      const providerRecord = existingProvider ?? await createProvider(
 306→        deps.surreal,
 307→        workspaceRecord,
 308→        {
 309→          name: new URL(config.authServerUrl).hostname,
 310→          display_name: new URL(config.authServerUrl).hostname,
 311→          auth_method: "oauth2",
 312→          authorization_url: config.authorizationEndpoint,
 313→          token_url: config.tokenEndpoint,
 314→          discovery_source: server.url,
 315→          ...(config.scopesSupported ? { scopes: config.scopesSupported } : {}),
 316→        },
 317→      );
 318→
 319→      // Track client_id: from existing provider or dynamic registration
 320→      let clientId: string | undefined = existingProvider?.client_id;
 321→
 322→      const wsId = workspaceRecord.id as string;
 323→
 324→      // Dynamic client registration (RFC 7591) — only for newly created providers
 325→      if (config.registrationEndpoint && !existingProvider) {
 326→        try {
 327→          const redirectUri = `${deps.config.baseUrl}/api/workspaces/${wsId}/mcp-servers/oauth/callback`;
 328→          const registrationResult = await registerDynamicClient(
 329→            config.registrationEndpoint,
 330→            {
 331→              client_name: "Brain",
 332→              redirect_uris: [redirectUri],
 333→              grant_types: ["authorization_code"],
 334→              response_types: ["code"],
 335→              token_endpoint_auth_method: "none",
 336→            },
 337→          );
 338→
 339→          clientId = registrationResult.client_id;
 340→
 341→          const encryptionKey = deps.config.toolEncryptionKey;
 342→          const clientSecretEncrypted = registrationResult.client_secret && encryptionKey
 343→            ? encryptSecret(registrationResult.client_secret, encryptionKey)
 344→            : undefined;
 345→
 346→          await updateProviderClientRegistration(
 347→            deps.surreal,
 348→            providerRecord.id,
 349→            registrationResult.client_id,
 350→            clientSecretEncrypted,
 351→          );
 352→        } catch (regError) {
 353→          log.error("mcp-server.auto-discover", "Dynamic client registration failed", regError, {
 354→            serverId: server.id.id as string,
 355→          });
 356→        }
 357→      }
 358→
 359→      // Link mcp_server to provider
 360→      await updateMcpServerProvider(deps.surreal, server.id, providerRecord.id);
 361→
 362→      // No client_id means the auth server doesn't support dynamic registration
 363→      // and no client_id was pre-configured. User should use static_headers instead.
 364→      if (!clientId) {
 365→        log.error("mcp-server.auto-discover", "No client_id available — authorization server does not support dynamic client registration", undefined, {
 366→          serverId: server.id.id as string,
 367→          authServer: config.authServerUrl,
 368→        });
 369→        return { error: "The authorization server does not support dynamic client registration." };
 370→      }
 371→
 372→      // Generate PKCE + authorization URL
 373→      const pkce = await generatePkce();
 374→      const state = crypto.randomUUID();
 375→
 376→      await storePendingOAuthState(deps.surreal, server.id, pkce.codeVerifier, state);
 377→
 378→      const redirectUri = `${deps.config.baseUrl}/api/workspaces/${wsId}/mcp-servers/oauth/callback`;
