 563→  async function handleUpdateHeaders(
 564→    workspaceId: string,
 565→    serverId: string,
 566→    request: Request,
 567→  ): Promise<Response> {
 568→    let workspaceRecord: RecordId<"workspace", string>;
 569→    try {
 570→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 571→    } catch (error) {
 572→      if (error instanceof HttpError) {
 573→        return jsonError(error.message, error.status);
 574→      }
 575→      log.error("mcp-server.update-headers", "Failed to resolve workspace", error, { workspaceId });
 576→      return jsonError("internal error", 500);
 577→    }
 578→
 579→    let body: { headers?: Array<{ name?: string; value?: string }> };
 580→    try {
 581→      body = await request.json() as { headers?: Array<{ name?: string; value?: string }> };
 582→    } catch {
 583→      return jsonError("invalid JSON body", 400);
 584→    }
 585→
 586→    if (!Array.isArray(body.headers)) {
 587→      return jsonError("headers array is required", 400);
 588→    }
 589→
 590→    const serverRecord = new RecordId("mcp_server", serverId);
 591→
 592→    // Empty headers array = clear all headers and reset auth_mode to "none"
 593→    if (body.headers.length === 0) {
 594→      const clearedRow = await clearMcpServerHeaders(
 595→        deps.surreal,
 596→        serverRecord,
 597→        workspaceRecord,
 598→      );
 599→
 600→      if (!clearedRow) {
 601→        return jsonError("MCP server not found", 404);
 602→      }
 603→
 604→      return jsonResponse(toMcpServerResponse(clearedRow), 200);
 605→    }
 606→
 607→    // Validate each header entry
 608→    for (const header of body.headers) {
 609→      if (!header.name || !header.value) {
 610→        return jsonError("Each header must have name and value", 400);
 611→      }
 612→    }
 613→    const headerValidation = validateHeaders(
 614→      body.headers as Array<{ name: string; value: string }>,
 615→    );
 616→    if (!headerValidation.ok) {
 617→      return jsonError(headerValidation.error, 400);
 618→    }
 619→
 620→    const encryptionKey = deps.config.toolEncryptionKey;
 621→    if (!encryptionKey) {
 622→      log.error("mcp-server.update-headers", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
 623→      return jsonError("Server encryption not configured", 500);
 624→    }
 625→
 626→    const encryptedHeaders = encryptHeaders(
 627→      body.headers as Array<{ name: string; value: string }>,
 628→      encryptionKey,
 629→    );
 630→
 631→    const updatedRow = await updateMcpServerHeaders(
 632→      deps.surreal,
 633→      serverRecord,
 634→      workspaceRecord,
 635→      encryptedHeaders,
 636→    );
 637→
 638→    if (!updatedRow) {
 639→      return jsonError("MCP server not found", 404);
 640→    }
 641→
 642→    return jsonResponse(toMcpServerResponse(updatedRow), 200);
 643→  }
