 645→  async function handleDiscoverAuth(
 646→    workspaceId: string,
 647→    serverId: string,
 648→    _request: Request,
 649→  ): Promise<Response> {
 650→    const resolved = await resolveServer(workspaceId, serverId);
 651→    if ("error" in resolved) return resolved.error;
 652→
 653→    const server = resolved.server;
 654→
 655→    try {
 656→      const config = await discoverAuth(server.url);
 657→
 658→      if (!config) {
 659→        const response: DiscoverAuthResponse = {
 660→          discovered: false,
 661→          error: "No OAuth metadata found at the MCP server URL",
 662→        };
 663→        return jsonResponse(response, 200);
 664→      }
 665→
 666→      // Find or create credential_provider from discovery (dedup by discovery_source)
 667→      const authServerHostname = new URL(config.authServerUrl).hostname;
 668→      const existingProvider = await findProviderByDiscoverySource(
 669→        deps.surreal,
 670→        server.workspace,
 671→        server.url,
 672→      );
 673→      const providerRecord = existingProvider ?? await createProvider(
 674→        deps.surreal,
 675→        server.workspace,
 676→        {
 677→          name: authServerHostname,
 678→          display_name: authServerHostname,
 679→          auth_method: "oauth2",
 680→          authorization_url: config.authorizationEndpoint,
 681→          token_url: config.tokenEndpoint,
 682→          discovery_source: server.url,
 683→          ...(config.scopesSupported ? { scopes: config.scopesSupported } : {}),
 684→        },
 685→      );
 686→
 687→      // Dynamic client registration (RFC 7591) — only for newly created providers
 688→      if (config.registrationEndpoint && !existingProvider) {
 689→        try {
 690→          const redirectUri = `${deps.config.baseUrl}/api/workspaces/${workspaceId}/mcp-servers/oauth/callback`;
 691→
 692→          const registrationResult = await registerDynamicClient(
 693→            config.registrationEndpoint,
 694→            {
 695→              client_name: "Brain",
 696→              redirect_uris: [redirectUri],
 697→              grant_types: ["authorization_code"],
 698→              response_types: ["code"],
 699→              token_endpoint_auth_method: "none",
 700→            },
 701→          );
 702→
 703→          const encryptionKey = deps.config.toolEncryptionKey;
 704→          const clientSecretEncrypted = registrationResult.client_secret && encryptionKey
 705→            ? encryptSecret(registrationResult.client_secret, encryptionKey)
 706→            : undefined;
 707→
 708→          await updateProviderClientRegistration(
 709→            deps.surreal,
 710→            providerRecord.id,
 711→            registrationResult.client_id,
 712→            clientSecretEncrypted,
 713→          );
 714→        } catch (regError) {
 715→          log.error("mcp-server.discover-auth", "Dynamic client registration failed", regError, { serverId: server.id.id as string });
 716→          // Non-fatal: proceed without dynamic registration
 717→        }
 718→      }
 719→
 720→      // Link mcp_server to the new provider
 721→      await updateMcpServerProvider(
 722→        deps.surreal,
 723→        server.id,
 724→        providerRecord.id,
 725→      );
 726→
 727→      const response: DiscoverAuthResponse = {
 728→        discovered: true,
 729→        auth_server: config.authServerUrl,
 730→        authorization_endpoint: config.authorizationEndpoint,
 731→        token_endpoint: config.tokenEndpoint,
 732→        scopes_supported: config.scopesSupported,
 733→        supports_dynamic_registration: config.registrationEndpoint !== undefined,
 734→        provider_id: providerRecord.id.id as string,
 735→      };
 736→
 737→      return jsonResponse(response, 200);
 738→    } catch (error) {
 739→      log.error("mcp-server.discover-auth", "OAuth discovery failed", error, { serverId });
 740→      return jsonError(
 741→        `OAuth discovery failed: ${error instanceof Error ? error.message : "unknown error"}`,
 742→        502,
 743→      );
 744→    }
 745→  }
