155→        const response = await fetch(
156→          `/api/workspaces/${encodeURIComponent(workspaceId)}/mcp-servers`,
157→          {
158→            method: "POST",
159→            headers: { "Content-Type": "application/json" },
160→            body: JSON.stringify(payload),
161→          },
162→        );
163→        if (!response.ok) {
164→          const text = await response.text();
165→          try {
166→            const body = JSON.parse(text) as { error?: string };
167→            return { error: (body.error ?? text) || "Failed to add server" };
168→          } catch {
169→            return { error: text || "Failed to add server" };
170→          }
171→        }
172→        const data = (await response.json()) as { authorization_url?: string };
173→
174→        // If the server supports OAuth, the backend auto-discovered and generated
175→        // an authorization URL — open it so the user can authorize immediately.
176→        if (data.authorization_url) {
177→          window.open(data.authorization_url, "_blank");
178→        }
179→
180→        refreshMcpServers();
181→        refreshProviders();
182→        return {};
183→      } catch {
184→        return { error: "Network error" };
185→      }
186→    },
187→    [workspaceId, refreshMcpServers, refreshProviders],
188→  );
