140→// ---------------------------------------------------------------------------
141→// Relative time formatting
142→// ---------------------------------------------------------------------------
143→
144→const relativeFormatter = new Intl.RelativeTimeFormat(undefined, { numeric: "auto" });
145→
146→function formatRelativeTime(isoDate?: string): string {
147→  if (!isoDate) return "Never";
148→  const diffMs = Date.now() - new Date(isoDate).getTime();
149→  const diffSeconds = Math.floor(diffMs / 1000);
150→  if (diffSeconds < 60) return relativeFormatter.format(-diffSeconds, "second");
151→  const diffMinutes = Math.floor(diffSeconds / 60);
152→  if (diffMinutes < 60) return relativeFormatter.format(-diffMinutes, "minute");
153→  const diffHours = Math.floor(diffMinutes / 60);
154→  if (diffHours < 24) return relativeFormatter.format(-diffHours, "hour");
155→  const diffDays = Math.floor(diffHours / 24);
156→  return relativeFormatter.format(-diffDays, "day");
157→}
