470→export function AddMcpServerDialog({
471→  onSubmit,
472→  existingNames,
473→  providers,
474→  trigger,
475→}: AddMcpServerDialogProps) {
476→  const [open, setOpen] = useState(false);
477→  const [formData, setFormData] = useState<AddMcpServerFormData>(initialFormData);
478→  const [submitting, setSubmitting] = useState(false);
479→  const [submitError, setSubmitError] = useState<string | undefined>();
480→
481→  const validation = validateAddMcpServerForm(formData, existingNames);
482→
483→  const handleFieldChange = useCallback(
484→    (field: AddMcpServerFieldName, value: string) => {
485→      setFormData((prev) => ({ ...prev, [field]: value }));
486→      setSubmitError(undefined);
487→    },
488→    [],
489→  );
490→
491→  const handleAuthModeChange = useCallback((mode: string) => {
492→    setFormData((prev) => ({
493→      ...prev,
494→      auth_mode: mode as AuthMode,
495→      // Reset mode-specific fields
496→      static_headers: mode === "static_headers" ? [{ name: "", value: "" }] : [],
497→      credentialProviderId: mode === "provider" ? prev.credentialProviderId : undefined,
498→    }));
499→    setSubmitError(undefined);
500→  }, []);
501→
502→  const handleHeadersChange = useCallback((headers: StaticHeaderEntry[]) => {
503→    setFormData((prev) => ({ ...prev, static_headers: headers }));
504→  }, []);
505→
506→  const handleSubmit = useCallback(async () => {
507→    if (!validation.isValid || submitting) return;
508→
509→    setSubmitting(true);
510→    setSubmitError(undefined);
511→
512→    const result = await onSubmit(formData);
513→
514→    setSubmitting(false);
515→    if (result.error) {
516→      setSubmitError(result.error);
517→    } else {
518→      setOpen(false);
519→      setFormData(initialFormData());
520→    }
521→  }, [validation.isValid, submitting, formData, onSubmit]);
522→
523→  const handleOpenChange = useCallback(
524→    (nextOpen: boolean) => {
525→      setOpen(nextOpen);
526→      if (!nextOpen && !submitting) {
527→        setFormData(initialFormData());
528→        setSubmitError(undefined);
529→      }
530→    },
531→    [submitting],
532→  );
533→
534→  return (
535→    <Dialog open={open} onOpenChange={handleOpenChange}>
536→      <DialogTrigger render={trigger ?? <Button size="sm">Add MCP Server</Button>} />
537→      <DialogContent className="sm:max-w-md">
