557→            )}
558→          </div>
559→
560→          <div className="flex flex-col gap-1.5">
561→            <Label htmlFor="mcp-url">URL</Label>
562→            <Input
563→              id="mcp-url"
564→              type="url"
565→              placeholder="https://mcp-server.example.com"
566→              value={formData.url}
567→              onChange={(e) => handleFieldChange("url", e.target.value)}
568→              aria-invalid={validation.errors.url ? true : undefined}
