 1→import { useCallback, useEffect, useState } from "react";
 2→import { useWorkspaceState } from "../stores/workspace-state";
 3→
 4→export type McpServerListItem = {
 5→  id: string;
 6→  name: string;
 7→  url: string;
 8→  transport: string;
 9→  auth_mode: string;
10→  has_static_headers: boolean;
11→  last_status?: string;
12→  last_error?: string;
13→  provider_id?: string;
14→  provider_name?: string;
15→  tool_count: number;
16→  created_at: string;
17→};
18→
19→type UseMcpServersReturn = {
20→  mcpServers: McpServerListItem[];
21→  isLoading: boolean;
22→  error?: string;
23→  refresh: () => void;
24→};
25→
26→/** Pure function: builds the API URL for fetching MCP servers. */
27→export function buildMcpServersUrl(workspaceId: string): string {
28→  return `/api/workspaces/${encodeURIComponent(workspaceId)}/mcp-servers`;
29→}
30→
31→export function useMcpServers(): UseMcpServersReturn {
32→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
33→  const [mcpServers, setMcpServers] = useState<McpServerListItem[]>([]);
34→  const [isLoading, setIsLoading] = useState(false);
35→  const [error, setError] = useState<string | undefined>();
36→
37→  const fetchMcpServers = useCallback(async () => {
38→    if (!workspaceId) return;
39→
40→    setIsLoading(true);
41→    setError(undefined);
42→
43→    try {
44→      const url = buildMcpServersUrl(workspaceId);
45→      const response = await fetch(url);
46→      if (!response.ok) {
47→        const body = await response.text();
48→        throw new Error(body);
49→      }
50→      const data = (await response.json()) as { servers: McpServerListItem[] };
51→      setMcpServers(data.servers);
52→    } catch (err) {
53→      setError(err instanceof Error ? err.message : "Failed to load MCP servers");
54→    } finally {
55→      setIsLoading(false);
56→    }
57→  }, [workspaceId]);
58→
59→  useEffect(() => {
60→    if (!workspaceId) return;
61→    void fetchMcpServers();
62→  }, [workspaceId, fetchMcpServers]);
63→
64→  const refresh = useCallback(() => {
65→    void fetchMcpServers();
66→  }, [fetchMcpServers]);
67→
68→  return { mcpServers, isLoading, error, refresh };
69→}
