 38→  { id: "providers", label: "Providers" },
 39→  { id: "accounts", label: "Accounts" },
 40→] as const;
 41→
 42→export const TOOL_REGISTRY_TABS: readonly ToolRegistryTab[] = [
 43→  ...PRIMARY_TABS,
 44→  ...ADVANCED_TABS,
 45→] as const;
 46→
 47→const VALID_TAB_IDS = new Set<string>(TOOL_REGISTRY_TABS.map((t) => t.id));
 48→const DEFAULT_TAB: ToolRegistryTabId = "tools";
 49→
 50→// ---------------------------------------------------------------------------
 51→// Pure view model
 52→// ---------------------------------------------------------------------------
 53→
 54→export type ToolRegistryPageInput = {
 55→  tabParam?: string;
 56→  toolsCount: number;
 57→  providersCount: number;
 58→  accountsCount: number;
 59→  mcpServersCount: number;
 60→};
 61→
 62→export type ToolRegistryViewModel = {
 63→  activeTab: ToolRegistryTabId;
 64→  showEmptyState: boolean;
 65→  tabLabels: Record<ToolRegistryTabId, string>;
 66→};
 67→
 68→function countForTab(
 69→  tabId: ToolRegistryTabId,
 70→  input: ToolRegistryPageInput,
 71→): number {
 72→  switch (tabId) {
 73→    case "servers":
 74→      return input.mcpServersCount;
 75→    case "tools":
 76→      return input.toolsCount;
 77→    case "providers":
 78→      return input.providersCount;
 79→    case "accounts":
 80→      return input.accountsCount;
 81→    case "access":
 82→      return input.toolsCount;
 83→  }
 84→}
 85→
 86→function formatTabLabel(baseLabel: string, count: number): string {
 87→  return count > 0 ? `${baseLabel} (${count})` : baseLabel;
 88→}
 89→
 90→export function deriveToolRegistryViewModel(
 91→  input: ToolRegistryPageInput,
 92→): ToolRegistryViewModel {
 93→  const activeTab: ToolRegistryTabId =
 94→    input.tabParam && VALID_TAB_IDS.has(input.tabParam)
 95→      ? (input.tabParam as ToolRegistryTabId)
 96→      : DEFAULT_TAB;
 97→
 98→  const activeCount = countForTab(activeTab, input);
 99→  const showEmptyState = activeCount === 0;
100→
101→  const tabLabels = Object.fromEntries(
102→    TOOL_REGISTRY_TABS.map((tab) => [
103→      tab.id,
104→      formatTabLabel(tab.label, countForTab(tab.id, input)),
105→    ]),
106→  ) as Record<ToolRegistryTabId, string>;
107→
108→  return {
109→    activeTab,
110→    showEmptyState,
111→    tabLabels,
112→  };
113→}
