354→    mcpServersCount: mcpServers.length,
355→  });
356→
357→  const handleTabChange = useCallback(
358→    (value: string) => {
359→      void navigate({
360→        to: "/tools",
361→        search: { tab: value },
362→      } as never);
363→    },
364→    [navigate],
365→  );
366→
367→  return (
368→    <section className="mx-auto flex max-w-5xl flex-col gap-4 p-6">
369→      <div className="flex items-center justify-between">
370→        <h1 className="text-lg font-semibold text-foreground">Tool Registry</h1>
371→      </div>
372→      <Tabs value={vm.activeTab} onValueChange={handleTabChange}>
373→        <TabsList variant="line">
374→          {PRIMARY_TABS.map((tab) => (
375→            <TabsTrigger key={tab.id} value={tab.id}>
376→              {vm.tabLabels[tab.id]}
377→            </TabsTrigger>
378→          ))}
379→          <span className="mx-2 h-4 w-px bg-border" aria-hidden="true" />
380→          {ADVANCED_TABS.map((tab) => (
381→            <TabsTrigger key={tab.id} value={tab.id} className="text-muted-foreground/60">
382→              {vm.tabLabels[tab.id]}
383→            </TabsTrigger>
384→          ))}
385→        </TabsList>
386→        <TabsContent value="servers">
387→          <div className="py-2">
388→            <McpServerSection
389→              servers={mcpServers}
390→              providers={providers}
391→              onAddServer={handleAddServer}
392→              onRemoveServer={handleRemoveServer}
393→              onDiscover={handleDiscoverTools}
394→              onSync={handleSyncTools}
395→              onAuthorize={handleAuthorize}
396→            />
397→          </div>
398→        </TabsContent>
399→        <TabsContent value="tools">
400→          {vm.showEmptyState && vm.activeTab === "tools" ? (
401→            <EmptyState message="No tools discovered yet." />
402→          ) : (
403→            <div className="flex flex-col gap-3 py-2">
404→              <div className="flex items-center gap-2">
405→                <input
406→                  type="text"
407→                  placeholder="Search tools..."
408→                  value={toolFilters.searchText}
409→                  onChange={(e) => handleToolSearchChange(e.target.value)}
410→                  className="h-8 rounded-md border px-3 text-sm"
411→                />
412→                <select
413→                  value={toolFilters.status ?? ""}
414→                  onChange={(e) =>
415→                    handleToolStatusFilterChange(e.target.value || undefined)
416→                  }
417→                  className="h-8 rounded-md border px-2 text-sm"
418→                >
419→                  <option value="">All statuses</option>
420→                  <option value="active">Active</option>
421→                  <option value="disabled">Disabled</option>
422→                </select>
423→                <select
424→                  value={toolFilters.riskLevel ?? ""}
425→                  onChange={(e) =>
426→                    handleToolRiskFilterChange(e.target.value || undefined)
427→                  }
428→                  className="h-8 rounded-md border px-2 text-sm"
429→                >
430→                  <option value="">All risk levels</option>
431→                  <option value="low">Low</option>
432→                  <option value="medium">Medium</option>
433→                  <option value="high">High</option>
434→                  <option value="critical">Critical</option>
435→                </select>
436→              </div>
437→              <ToolTable tools={tools} filters={toolFilters} />
438→            </div>
439→          )}
440→        </TabsContent>
441→        <TabsContent value="providers">
442→          {providers.length === 0 ? (
443→            <EmptyState
444→              message="No credential providers configured."
445→              action={<CreateProviderDialog onSubmit={handleCreateProvider} />}
446→            />
447→          ) : (
448→            <>
449→              <div className="flex justify-end py-2">
450→                <CreateProviderDialog onSubmit={handleCreateProvider} />
451→              </div>
452→              <ProviderTable providers={providers} onDelete={handleDeleteProvider} />
453→            </>
454→          )}
455→        </TabsContent>
456→        <TabsContent value="accounts">
457→          {vm.showEmptyState && vm.activeTab === "accounts" ? (
458→            <EmptyState message="No accounts connected." />
459→          ) : (
460→            <AccountTable
461→              accounts={accounts}
462→              providers={providerInfoList}
463→              onRevoke={handleRevokeAccount}
464→              onReconnect={handleReconnectAccount}
465→            />
466→          )}
467→        </TabsContent>
468→        <TabsContent value="access">
469→          {accessToast && (
470→            <div className="mb-3 rounded-md border border-amber-300 bg-amber-50 px-4 py-2 text-sm text-amber-800">
471→              {accessToast}
472→              <button
473→                className="ml-2 font-medium underline"
474→                onClick={() => setAccessToast(undefined)}
475→              >
476→                Dismiss
477→              </button>
478→            </div>
479→          )}
480→          {vm.showEmptyState && vm.activeTab === "access" ? (
481→            <EmptyState message="No tools available to manage access." />
482→          ) : (
483→            <GrantTable
484→              tools={tools}
485→              grantsByToolId={grantsByToolId}
486→              onGrantAccess={(_toolId) => {
487→                // CreateGrantDialog will be opened by the GrantTable component
488→              }}
489→              onRevokeGrant={handleRevokeGrant}
490→            />
491→          )}
492→        </TabsContent>
493→      </Tabs>
494→    </section>
495→  );
496→}
497→
498→// ---------------------------------------------------------------------------
499→// Empty state component
500→// ---------------------------------------------------------------------------

