 528→  async function handleSync(
 529→    workspaceId: string,
 530→    serverId: string,
 531→    request: Request,
 532→  ): Promise<Response> {
 533→    const resolved = await resolveServer(workspaceId, serverId);
 534→    if ("error" in resolved) return resolved.error;
 535→
 536→    const server = resolved.server as unknown as McpServerRecord;
 537→
 538→    let selectedTools: string[] | undefined;
 539→    try {
 540→      const body = await request.json() as { selected_tools?: string[] };
 541→      selectedTools = body.selected_tools;
