 563→  async function handleUpdateHeaders(
 564→    workspaceId: string,
 565→    serverId: string,
 566→    request: Request,
 567→  ): Promise<Response> {
 568→    let workspaceRecord: RecordId<"workspace", string>;
 569→    try {
 570→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 571→    } catch (error) {
 572→      if (error instanceof HttpError) {
 573→        return jsonError(error.message, error.status);
 574→      }
 575→      log.error("mcp-server.update-headers", "Failed to resolve workspace", error, { workspaceId });
 576→      return jsonError("internal error", 500);
 577→    }
 578→
 579→    let body: { headers?: Array<{ name?: string; value?: string }> };
 580→    try {
 581→      body = await request.json() as { headers?: Array<{ name?: string; value?: string }> };
 582→    } catch {
 583→      return jsonError("invalid JSON body", 400);
 584→    }
 585→
 586→    if (!Array.isArray(body.headers)) {
 587→      return jsonError("headers array is required", 400);
 588→    }
 589→
 590→    const serverRecord = new RecordId("mcp_server", serverId);
 591→
 592→    // Empty headers array = clear all headers and reset auth_mode to "none"
 593→    if (body.headers.length === 0) {
 594→      const clearedRow = await clearMcpServerHeaders(
 595→        deps.surreal,
 596→        serverRecord,
 597→        workspaceRecord,
 598→      );
 599→
 600→      if (!clearedRow) {
 601→        return jsonError("MCP server not found", 404);
 602→      }
 603→
 604→      return jsonResponse(toMcpServerResponse(clearedRow), 200);
 605→    }
 606→
 607→    // Validate each header entry
 608→    for (const header of body.headers) {
 609→      if (!header.name || !header.value) {
 610→        return jsonError("Each header must have name and value", 400);
 611→      }
 612→    }
 613→    const headerValidation = validateHeaders(
 614→      body.headers as Array<{ name: string; value: string }>,
 615→    );
 616→    if (!headerValidation.ok) {
 617→      return jsonError(headerValidation.error, 400);
 618→    }
 619→
 620→    const encryptionKey = deps.config.toolEncryptionKey;
 621→    if (!encryptionKey) {
 622→      log.error("mcp-server.update-headers", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
 623→      return jsonError("Server encryption not configured", 500);
 624→    }
 625→
 626→    const encryptedHeaders = encryptHeaders(
 627→      body.headers as Array<{ name: string; value: string }>,
 628→      encryptionKey,
 629→    );
 630→
 631→    const updatedRow = await updateMcpServerHeaders(
 632→      deps.surreal,
 633→      serverRecord,
 634→      workspaceRecord,
 635→      encryptedHeaders,
 636→    );
 637→
 638→    if (!updatedRow) {
 639→      return jsonError("MCP server not found", 404);
 640→    }
 641→
 642→    return jsonResponse(toMcpServerResponse(updatedRow), 200);
 643→  }
 644→
 645→  async function handleDiscoverAuth(
 646→    workspaceId: string,
 647→    serverId: string,
 648→    _request: Request,
 649→  ): Promise<Response> {
 650→    const resolved = await resolveServer(workspaceId, serverId);
 651→    if ("error" in resolved) return resolved.error;
 652→
 653→    const server = resolved.server;
 654→
 655→    try {
 656→      const config = await discoverAuth(server.url);
 657→
 658→      if (!config) {
 659→        const response: DiscoverAuthResponse = {
 660→          discovered: false,
 661→          error: "No OAuth metadata found at the MCP server URL",
 662→        };
 663→        return jsonResponse(response, 200);
 664→      }
 665→
 666→      // Find or create credential_provider from discovery (dedup by discovery_source)
 667→      const authServerHostname = new URL(config.authServerUrl).hostname;
 668→      const existingProvider = await findProviderByDiscoverySource(
 669→        deps.surreal,
 670→        server.workspace,
 671→        server.url,
 672→      );
 673→      const providerRecord = existingProvider ?? await createProvider(
 674→        deps.surreal,
 675→        server.workspace,
 676→        {
 677→          name: authServerHostname,
 678→          display_name: authServerHostname,
 679→          auth_method: "oauth2",
 680→          authorization_url: config.authorizationEndpoint,
 681→          token_url: config.tokenEndpoint,
 682→          discovery_source: server.url,
 683→          ...(config.scopesSupported ? { scopes: config.scopesSupported } : {}),
 684→        },
 685→      );
 686→
 687→      // Dynamic client registration (RFC 7591) — only for newly created providers
 688→      if (config.registrationEndpoint && !existingProvider) {
 689→        try {
 690→          const redirectUri = `${deps.config.baseUrl}/api/workspaces/${workspaceId}/mcp-servers/oauth/callback`;
 691→
 692→          const registrationResult = await registerDynamicClient(
 693→            config.registrationEndpoint,
 694→            {
 695→              client_name: "Brain",
 696→              redirect_uris: [redirectUri],
 697→              grant_types: ["authorization_code"],
 698→              response_types: ["code"],
 699→              token_endpoint_auth_method: "none",
 700→            },
 701→          );
 702→
 703→          const encryptionKey = deps.config.toolEncryptionKey;
 704→          const clientSecretEncrypted = registrationResult.client_secret && encryptionKey
 705→            ? encryptSecret(registrationResult.client_secret, encryptionKey)
 706→            : undefined;
 707→
 708→          await updateProviderClientRegistration(
 709→            deps.surreal,
 710→            providerRecord.id,
 711→            registrationResult.client_id,
 712→            clientSecretEncrypted,
 713→          );
 714→        } catch (regError) {
 715→          log.error("mcp-server.discover-auth", "Dynamic client registration failed", regError, { serverId: server.id.id as string });
 716→          // Non-fatal: proceed without dynamic registration
 717→        }
 718→      }
 719→
 720→      // Link mcp_server to the new provider
 721→      await updateMcpServerProvider(
 722→        deps.surreal,
 723→        server.id,
 724→        providerRecord.id,
 725→      );
 726→
 727→      const response: DiscoverAuthResponse = {
 728→        discovered: true,
 729→        auth_server: config.authServerUrl,
 730→        authorization_endpoint: config.authorizationEndpoint,
 731→        token_endpoint: config.tokenEndpoint,
 732→        scopes_supported: config.scopesSupported,
 733→        supports_dynamic_registration: config.registrationEndpoint !== undefined,
 734→        provider_id: providerRecord.id.id as string,
 735→      };
 736→
 737→      return jsonResponse(response, 200);
 738→    } catch (error) {
 739→      log.error("mcp-server.discover-auth", "OAuth discovery failed", error, { serverId });
 740→      return jsonError(
 741→        `OAuth discovery failed: ${error instanceof Error ? error.message : "unknown error"}`,
 742→        502,
 743→      );
 744→    }
 745→  }
 746→
 747→  async function handleAuthorize(
 748→    workspaceId: string,
 749→    serverId: string,
 750→    _request: Request,
 751→  ): Promise<Response> {
 752→    const resolved = await resolveServer(workspaceId, serverId);
 753→    if ("error" in resolved) return resolved.error;
 754→
 755→    const server = resolved.server;
 756→
 757→    // Server must have a linked credential_provider (from discover-auth)
 758→    if (!server.provider) {
 759→      return jsonError("MCP server has no linked credential provider. Run discover-auth first.", 400);
 760→    }
 761→
 762→    const provider = await getProviderById(deps.surreal, server.provider.id as string);
 763→    if (!provider) {
 764→      return jsonError("Linked credential provider not found", 404);
 765→    }
 766→
 767→    const providerRecord = provider as unknown as {
 768→      authorization_url?: string;
 769→      client_id?: string;
 770→      scopes?: string[];
 771→    };
 772→
 773→    if (!providerRecord.authorization_url) {
 774→      return jsonError("Provider missing authorization_url", 400);
 775→    }
 776→
 777→    // Generate PKCE pair and random state
 778→    const pkce = await generatePkce();
 779→    const state = crypto.randomUUID();
 780→
 781→    // Store pending state on the mcp_server record (no module-level singletons)
 782→    await storePendingOAuthState(
 783→      deps.surreal,
 784→      server.id,
 785→      pkce.codeVerifier,
 786→      state,
 787→    );
 788→
 789→    // Build the redirect_uri (Brain's OAuth callback)
 790→    const redirectUri = `${deps.config.baseUrl}/api/workspaces/${workspaceId}/mcp-servers/oauth/callback`;
 791→
 792→    const clientId = providerRecord.client_id;
 793→    if (!clientId) {
 794→      return jsonError(
 795→        "Provider has no client_id. The authorization server may not support dynamic client registration. Use static_headers auth mode with a pre-issued token instead.",
 796→        400,
 797→      );
 798→    }
 799→
 800→    // Build authorization URL with PKCE and resource parameter
 801→    const authorizationParams: AuthorizationParams = {
 802→      authorizationEndpoint: providerRecord.authorization_url,
 803→      clientId,
 804→      redirectUri,
 805→      codeChallenge: pkce.codeChallenge,
 806→      state,
 807→      resource: server.url,
 808→      scope: providerRecord.scopes?.join(" "),
 809→    };
 810→
 811→    const redirectUrl = buildAuthorizationUrl(authorizationParams);
 812→
 813→    return jsonResponse({ redirect_url: redirectUrl, state }, 200);
 814→  }
 815→
 816→  async function handleOAuthCallback(
 817→    workspaceId: string,
 818→    request: Request,
 819→  ): Promise<Response> {
 820→    let workspaceRecord: RecordId<"workspace", string>;
 821→    try {
 822→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 823→    } catch (error) {
 824→      if (error instanceof HttpError) {
 825→        return jsonError(error.message, error.status);
 826→      }
 827→      log.error("mcp-server.oauth-callback", "Failed to resolve workspace", error, { workspaceId });
 828→      return jsonError("internal error", 500);
 829→    }
 830→
 831→    // Parse code + state from query params (GET redirect from OAuth provider)
 832→    // or request body (POST from frontend) for backwards compat
 833→    let code: string | undefined;
 834→    let state: string | undefined;
 835→
 836→    const url = new URL(request.url);
 837→    if (url.searchParams.has("code")) {
 838→      code = url.searchParams.get("code") ?? undefined;
 839→      state = url.searchParams.get("state") ?? undefined;
 840→    } else {
 841→      try {
 842→        const body = await request.json() as { code?: string; state?: string };
 843→        code = body.code;
 844→        state = body.state;
 845→      } catch {
 846→        return jsonError("invalid request", 400);
 847→      }
 848→    }
 849→
 850→    if (!code || typeof code !== "string") {
 851→      return jsonError("code is required", 400);
 852→    }
 853→    if (!state || typeof state !== "string") {
 854→      return jsonError("state is required", 400);
 855→    }
 856→
 857→    // Find the mcp_server that has this pending state
 858→    const server = await findServerByPendingState(deps.surreal, workspaceRecord, state);
 859→    if (!server) {
 860→      return jsonError("No pending authorization found for the provided state", 404);
 861→    }
 862→
 863→    if (!server.pending_pkce_verifier) {
 864→      return jsonError("Server missing PKCE code_verifier", 400);
 865→    }
 866→
 867→    // Load the linked credential_provider for token_endpoint
 868→    if (!server.provider) {
 869→      return jsonError("Server has no linked credential provider", 400);
 870→    }
 871→
 872→    const provider = await getProviderById(deps.surreal, server.provider.id as string);
 873→    if (!provider) {
 874→      return jsonError("Linked credential provider not found", 404);
 875→    }
 876→
 877→    const providerRecord = provider as unknown as {
 878→      token_url?: string;
 879→      client_id?: string;
 880→    };
 881→
 882→    if (!providerRecord.token_url) {
 883→      return jsonError("Provider missing token_url", 400);
 884→    }
 885→
 886→    // Build redirect_uri (must match the one used during authorize)
 887→    const redirectUri = `${deps.config.baseUrl}/api/workspaces/${workspaceId}/mcp-servers/oauth/callback`;
 888→
 889→    const clientId = providerRecord.client_id;
 890→    if (!clientId) {
 891→      const msg = "Provider has no client_id configured";
 892→      if (request.method === "GET") {
 893→        return Response.redirect(
 894→          `${deps.config.baseUrl}/tools?tab=servers&oauth=error`,
 895→          302,
 896→        );
 897→      }
 898→      return jsonError(msg, 400);
 899→    }
 900→
 901→    try {
 902→      // Exchange the authorization code for tokens using PKCE
 903→      const tokenResult = await exchangeCode({
 904→        tokenEndpoint: providerRecord.token_url,
 905→        code,
 906→        redirectUri,
 907→        codeVerifier: server.pending_pkce_verifier,
 908→        clientId,
 909→      });
 910→
 911→      // Encrypt tokens before storage
 912→      const encryptionKey = deps.config.toolEncryptionKey;
 913→      if (encryptionKey) {
 914→        // Find workspace owner identity for the connected_account
 915→        const ownerIdentity = await findWorkspaceOwnerIdentity(deps.surreal, workspaceRecord);
 916→        if (ownerIdentity) {
 917→          const accountContent: Record<string, unknown> = {
 918→            identity: ownerIdentity,
 919→            provider: server.provider,
 920→            workspace: workspaceRecord,
 921→            status: "active",
 922→            access_token_encrypted: encryptSecret(tokenResult.access_token, encryptionKey),
 923→          };
 924→
 925→          if (tokenResult.refresh_token) {
 926→            accountContent.refresh_token_encrypted = encryptSecret(tokenResult.refresh_token, encryptionKey);
 927→          }
 928→
 929→          if (tokenResult.expires_in) {
 930→            accountContent.token_expires_at = new Date(Date.now() + tokenResult.expires_in * 1000);
 931→          }
 932→
 933→          if (tokenResult.scope) {
 934→            accountContent.scopes = tokenResult.scope.split(" ");
 935→          }
 936→
 937→          const account = await createConnectedAccount(deps.surreal, accountContent);
 938→
 939→          // Link mcp_server to the new connected_account
 940→          await updateMcpServerOAuthAccount(deps.surreal, server.id, account.id);
 941→        }
 942→      }
 943→
 944→      // Clear pending PKCE state and mark server as authenticated
 945→      await clearPendingOAuthState(deps.surreal, server.id);
 946→      await updateMcpServerStatus(deps.surreal, server.id, "ok");
 947→
 948→      // Auto-sync tools now that OAuth is complete
 949→      triggerAutoSync(server as unknown as McpServerRecord);
 950→
 951→      // GET = browser redirect from OAuth provider → redirect back to UI
 952→      // POST = programmatic call → return JSON
 953→      if (request.method === "GET") {
 954→        return Response.redirect(
 955→          `${deps.config.baseUrl}/tools?tab=servers&oauth=success`,
 956→          302,
 957→        );
 958→      }
 959→      return jsonResponse(tokenResult, 200);
 960→    } catch (error) {
 961→      log.error("mcp-server.oauth-callback", "Token exchange failed", error, { workspaceId });
 962→      if (request.method === "GET") {
 963→        return Response.redirect(
 964→          `${deps.config.baseUrl}/tools?tab=servers&oauth=error`,
 965→          302,
 966→        );
 967→      }
 968→      return jsonError(
 969→        `Token exchange failed: ${error instanceof Error ? error.message : "unknown error"}`,
 970→        502,
 971→      );
 972→    }
 973→  }
 974→
 975→  async function handleGetAuthStatus(
 976→    workspaceId: string,
 977→    serverId: string,
 978→    _request: Request,
 979→  ): Promise<Response> {
 980→    let workspaceRecord: RecordId<"workspace", string>;
 981→    try {
 982→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 983→    } catch (error) {
 984→      if (error instanceof HttpError) {
 985→        return jsonError(error.message, error.status);
 986→      }
 987→      log.error("mcp-server.auth-status", "Failed to resolve workspace", error, { workspaceId });
 988→      return jsonError("internal error", 500);
 989→    }
 990→
 991→    const serverRecord = new RecordId("mcp_server", serverId);
 992→    const result = await getMcpServerAuthStatus(deps.surreal, serverRecord, workspaceRecord);
 993→
 994→    if (!result) {
 995→      return jsonError("MCP server not found", 404);
 996→    }
 997→
 998→    return jsonResponse(result, 200);
 999→  }
1000→
1001→  /**
1002→   * Fire-and-forget tool sync after server creation or successful OAuth.
1003→   * Errors are logged but never surface to the caller.
1004→   */
1005→  function triggerAutoSync(server: McpServerRecord): void {
1006→    const work = discoverTools(
1007→      { surreal: deps.surreal, mcpClientFactory: deps.mcpClientFactory, toolEncryptionKey: deps.config.toolEncryptionKey },
1008→      server,
1009→      { dryRun: false },
1010→    ).then(() => {
1011→      updateMcpServerStatus(deps.surreal, server.id, "ok").catch(() => undefined);
1012→    }).catch((error) => {
1013→      log.error("mcp-server.auto-sync", "Auto-sync failed", error, {
1014→        serverId: server.id.id as string,
1015→      });
1016→    });
1017→
1018→    deps.inflight.track(work);
1019→  }
1020→
1021→  return {
1022→    handleCreateServer,
1023→    handleListServers,
1024→    handleGetServerDetail,
1025→    handleDeleteServer,
1026→    handleDiscover,
1027→    handleDiscoverAuth,
1028→    handleAuthorize,
1029→    handleOAuthCallback,
1030→    handleSync,
1031→    handleUpdateHeaders,
1032→    handleGetAuthStatus,
1033→  };
1034→}
