const fs = require('fs');
const content = fs.readFileSync(process.env.FILE_CONTENT || '/dev/stdin', 'utf-8');
// Extract type definitions for ToolSyncDetail and related types
const lines = content.split('\n');
let inSection = false;
let output = [];
lines.forEach((line, idx) => {
  if (line.includes('ToolSync') || line.includes('ToolRisk') || line.includes('McpServer')) {
    inSection = true;
  }
  if (inSection) {
    output.push(`${idx+1}: ${line}`);
    if (line.includes('};') || line.includes('>;')) {
      // Print some context after
      if (output.length < 50) {
        for (let i = idx + 1; i < Math.min(idx + 3, lines.length); i++) {
          output.push(`${i+1}: ${lines[i]}`);
        }
      }
    }
  }
});
console.log(output.slice(0, 100).join('\n'));

