  1→/**
  2→ * Tool Registry Domain Types
  3→ *
  4→ * Credential providers, connected accounts, tools, grants, governance,
  5→ * MCP servers, and discovery.
  6→ *
  7→ * Auth method variants: oauth2, api_key, bearer, basic.
  8→ * Encrypted fields use _encrypted suffix (ADR-068).
  9→ */
 10→import type { RecordId } from "surrealdb";
 11→
 12→export type AuthMethod = "oauth2" | "api_key" | "bearer" | "basic";
 13→
 14→/**
 15→ * Input payload for creating a credential provider via API.
 16→ * client_secret is plaintext here -- encrypted before storage.
 17→ */
 18→export type CreateProviderInput = {
 19→  name: string;
 20→  display_name: string;
 21→  auth_method: AuthMethod;
 22→  authorization_url?: string;
 23→  token_url?: string;
 24→  client_id?: string;
 25→  client_secret?: string;
 26→  scopes?: string[];
 27→  api_key_header?: string;
 28→};
 29→
 30→/**
 31→ * SurrealDB record shape for credential_provider.
 32→ */
 33→export type CredentialProviderRecord = {
 34→  id: RecordId<"credential_provider", string>;
 35→  name: string;
 36→  display_name: string;
 37→  auth_method: AuthMethod;
 38→  workspace: RecordId<"workspace", string>;
 39→  authorization_url?: string;
 40→  token_url?: string;
 41→  client_id?: string;
 42→  client_secret_encrypted?: string;
 43→  scopes?: string[];
 44→  api_key_header?: string;
 45→  discovery_source?: string;
 46→  created_at: Date;
 47→};
 48→
 49→/**
 50→ * Status of a connected account.
 51→ */
 52→export type AccountStatus = "active" | "revoked" | "expired";
 53→
 54→/**
 55→ * Input payload for connecting an account via static credentials (API key, basic, bearer).
 56→ * OAuth2 connections are initiated via redirect flow -- no credentials in this payload.
 57→ */
 58→export type ConnectAccountInput = {
 59→  api_key?: string;
 60→  bearer_token?: string;
 61→  basic_username?: string;
 62→  basic_password?: string;
 63→};
 64→
 65→/**
 66→ * SurrealDB record shape for connected_account.
 67→ */
