306→// ---------------------------------------------------------------------------
307→// OAuth Discovery Types (RFC 9728 + RFC 8414)
308→// ---------------------------------------------------------------------------
309→
310→/**
311→ * Protected Resource Metadata (RFC 9728).
312→ * Returned by /.well-known/oauth-protected-resource on the MCP server.
313→ */
314→export type ProtectedResourceMetadata = {
315→  resource: string;
316→  authorization_servers: string[];
317→  scopes_supported?: string[];
318→  bearer_methods_supported?: string[];
319→};
320→
321→/**
322→ * Authorization Server Metadata (RFC 8414).
323→ * Returned by /.well-known/oauth-authorization-server on the auth server.
324→ */
325→export type AuthServerMetadata = {
326→  issuer: string;
327→  authorization_endpoint: string;
328→  token_endpoint: string;
329→  registration_endpoint?: string;
330→  scopes_supported?: string[];
331→  response_types_supported: string[];
332→  code_challenge_methods_supported?: string[];
333→  grant_types_supported?: string[];
334→};
335→
336→/**
337→ * Discovered auth configuration -- pure domain type produced by discovery pipeline.
338→ */
339→export type DiscoveredAuthConfig = {
340→  authServerUrl: string;
341→  authorizationEndpoint: string;
342→  tokenEndpoint: string;
343→  registrationEndpoint?: string;
344→  scopesSupported?: string[];
345→  supportsS256: boolean;
346→  resourceUri: string;
347→};
348→
349→/**
350→ * API response shape for discover-auth endpoint.
351→ */
352→export type DiscoverAuthResponse =
353→  | {
354→      discovered: true;
355→      auth_server: string;
356→      authorization_endpoint: string;
357→      token_endpoint: string;
358→      scopes_supported?: string[];
359→      supports_dynamic_registration: boolean;
360→      provider_id?: string;
361→    }
362→  | {
363→      discovered: false;
364→      error: string;
365→    };
366→
367→// ---------------------------------------------------------------------------
368→// PKCE / Authorization Types (OAuth 2.1 + RFC 8707)
369→// ---------------------------------------------------------------------------
370→
371→/**
372→ * PKCE S256 code challenge pair.
373→ * codeVerifier: 43-128 chars of unreserved characters.
374→ * codeChallenge: BASE64URL(SHA256(codeVerifier)).
375→ */
376→export type PkceChallenge = {
377→  codeVerifier: string;
378→  codeChallenge: string;
379→};
380→
381→/**
382→ * Parameters for building an OAuth 2.1 authorization URL.
383→ */
384→export type AuthorizationParams = {
385→  authorizationEndpoint: string;
386→  clientId: string;
387→  redirectUri: string;
388→  codeChallenge: string;
389→  state: string;
390→  resource: string;
391→  scope?: string;
392→};
393→
394→/**
395→ * Parameters for building a token exchange request (PKCE).
396→ * Pure data -- used by buildTokenRequest to produce { url, body, headers }.
397→ */
398→export type TokenExchangeParams = {
399→  tokenEndpoint: string;
400→  code: string;
401→  redirectUri: string;
402→  codeVerifier: string;
403→  clientId: string;
404→};
405→
406→/**
407→ * Token response from the authorization server's token endpoint.
408→ */
409→export type TokenResult = {
410→  access_token: string;
411→  token_type: string;
412→  expires_in?: number;
413→  refresh_token?: string;
414→  scope?: string;
415→};
416→
417→// ---------------------------------------------------------------------------
418→// Resolved Tool (extends proxy type with source server)
419→// ---------------------------------------------------------------------------
420→
421→/**
422→ * Resolved tool from Brain's can_use graph query.
423→ * Extends the proxy's tool format with optional source_server_id
424→ * for tools discovered from MCP servers.
425→ */
426→export type ResolvedTool = {
